INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$Which Git command creates a local copy of a remote repository, including its full history and working tree?$gl$, $gl$[{"id":"a","text":"git pull"},{"id":"b","text":"git clone <url>"},{"id":"c","text":"git fetch <url>"},{"id":"d","text":"git init <url>"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git clone <url>` downloads the entire repository, history, and checks out the default branch. `git pull` updates an existing clone, `git fetch` only downloads objects/refs without merging, and `git init` creates a new empty repo (it takes a directory, not a URL).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which Git command creates a local copy of a remote repository, including its full history and working tree?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$You modified three tracked files but want to commit only one of them. Which sequence stages just `app.py` and records the commit?$gl$, $gl$[{"id":"a","text":"git commit app.py -m \"fix\""},{"id":"b","text":"git add app.py && git commit -m \"fix\""},{"id":"c","text":"git stage --all && git commit -m \"fix\""},{"id":"d","text":"git commit -a -m \"fix\""}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git add app.py` stages only that file, then `git commit -m` records the staged snapshot. `git commit -a` would commit all modified tracked files, and `git stage --all` stages everything.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You modified three tracked files but want to commit only one of them. Which sequence stages just `app.py` and records the commit?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$You have uncommitted local changes but need to switch branches quickly without committing. Which command shelves the changes for later restoration?$gl$, $gl$[{"id":"a","text":"git reset --hard"},{"id":"b","text":"git stash"},{"id":"c","text":"git checkout -- ."},{"id":"d","text":"git clean -fd"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git stash` saves modified tracked files and staged changes to a stack, restoring a clean working tree; `git stash pop` reapplies them. `git reset --hard` and `git checkout -- .` discard changes permanently, and `git clean -fd` deletes untracked files.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/stash.html","label":"GitLab Docs — Git stash"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You have uncommitted local changes but need to switch branches quickly without committing. Which command shelves the changes for later restoration?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: `git rebase` rewrites commit history by reapplying commits onto a new base, which can change commit SHAs.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Rebasing replays a branch's commits onto a different base commit, producing new commit objects with new SHAs. This is why rebasing shared/published branches is discouraged — it diverges history for collaborators.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: `git rebase` rewrites commit history by reapplying commits onto a new base, which can change commit SHAs.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$In GitLab Flow, what is the recommended relationship between feature branches and the main branch?$gl$, $gl$[{"id":"a","text":"Feature branches are created from main and merged back via merge request after review."},{"id":"b","text":"Feature branches are committed to directly on production servers."},{"id":"c","text":"Feature work is committed straight to main without branches."},{"id":"d","text":"Each developer maintains a permanent personal copy of main that is never merged."}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$GitLab Flow uses short-lived feature branches branched off main, integrated back through merge requests after review and CI. Committing directly to main or to production bypasses review and pipeline validation.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In GitLab Flow, what is the recommended relationship between feature branches and the main branch?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$A protected branch in GitLab, by default, prevents which action for users below the configured push role?$gl$, $gl$[{"id":"a","text":"Viewing the branch in the repository"},{"id":"b","text":"Pushing commits directly and force-pushing to that branch"},{"id":"c","text":"Creating issues that reference the branch"},{"id":"d","text":"Cloning the repository"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Protected branches restrict who can push and merge, and block force pushes by default, so changes must flow through merge requests. They do not affect read access, cloning, or issue creation.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A protected branch in GitLab, by default, prevents which action for users below the configured push role?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want to contribute to a project where you lack push access. Which GitLab workflow lets you propose changes from your own copy?$gl$, $gl$[{"id":"a","text":"Clone the project and push a new branch to the original repository"},{"id":"b","text":"Fork the project, push to your fork, then open a merge request to the upstream project"},{"id":"c","text":"Open an issue and attach a patch file"},{"id":"d","text":"Request the Owner role on the upstream project"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The fork workflow creates a server-side copy you control; you push branches there and open a merge request targeting the upstream project. You cannot push branches to a repo you lack access to, and issues are not a code-contribution mechanism.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want to contribute to a project where you lack push access. Which GitLab workflow lets you propose changes from your own copy?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which Git command creates an annotated tag `v1.0.0` on the current commit?$gl$, $gl$[{"id":"a","text":"git tag v1.0.0"},{"id":"b","text":"git tag -a v1.0.0 -m \"Release 1.0.0\""},{"id":"c","text":"git branch v1.0.0"},{"id":"d","text":"git commit --tag v1.0.0"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git tag -a <name> -m <msg>` creates an annotated tag (a full object with tagger, date, and message). `git tag v1.0.0` alone creates a lightweight tag, and `git branch` creates a branch, not a tag.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/tags/","label":"GitLab Docs — Tags"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which Git command creates an annotated tag `v1.0.0` on the current commit?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$By default, what is the file name and location GitLab looks for to define a project's CI/CD pipeline?$gl$, $gl$[{"id":"a","text":".gitlab-ci.yml in the repository root"},{"id":"b","text":"ci/pipeline.yaml in the repository root"},{"id":"c","text":".gitlab/config.yml in the project"},{"id":"d","text":"gitlab-pipeline.json in the repository root"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$GitLab reads the pipeline definition from `.gitlab-ci.yml` in the repository root by default (the path is configurable in project settings). The other paths are not GitLab defaults.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$By default, what is the file name and location GitLab looks for to define a project's CI/CD pipeline?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$In `.gitlab-ci.yml`, jobs that belong to the same `stage` behave how relative to each other?$gl$, $gl$[{"id":"a","text":"They run sequentially in the order written"},{"id":"b","text":"They run in parallel, and the next stage starts only after all jobs in the current stage succeed"},{"id":"c","text":"Only the first job in the stage runs; the rest are skipped"},{"id":"d","text":"They each trigger a separate pipeline"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Jobs in the same stage run in parallel (subject to runner availability). The pipeline advances to the next stage only when every job in the current stage passes (unless `allow_failure` is set).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In `.gitlab-ci.yml`, jobs that belong to the same `stage` behave how relative to each other?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about `artifacts` and `cache` in GitLab CI/CD.$gl$, $gl$[{"id":"a","text":"artifacts are uploaded to GitLab and can be passed to jobs in later stages and downloaded from the UI."},{"id":"b","text":"cache is intended to speed up jobs by reusing files (e.g. dependencies) between pipeline runs and is best-effort."},{"id":"c","text":"cache is guaranteed to always be available and is the correct way to pass build outputs between stages."},{"id":"d","text":"artifacts have a configurable expiry via expire_in."}]$gl$::jsonb, $gl$["a","b","d"]$gl$::jsonb, $gl$Artifacts are stored by GitLab, passed downstream, downloadable, and can expire via `expire_in`. Cache is a best-effort optimization for reuse between runs and is NOT guaranteed; build outputs that must reach later stages should use artifacts, not cache.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"},{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about `artifacts` and `cache` in GitLab CI/CD.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want a `deploy` job to start as soon as its `build` job finishes, without waiting for other jobs in the build stage. Which keyword expresses this dependency?$gl$, $gl$[{"id":"a","text":"only: [build]"},{"id":"b","text":"needs: [build]"},{"id":"c","text":"dependencies: build"},{"id":"d","text":"when: on_success"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`needs` creates a directed acyclic graph (DAG): a job runs as soon as its listed `needs` jobs complete, ignoring stage ordering. `dependencies` only controls which artifacts are downloaded; `only` controls job inclusion; `when` controls run conditions.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/needs.html","label":"GitLab Docs — needs / DAG pipelines"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want a `deploy` job to start as soon as its `build` job finishes, without waiting for other jobs in the build stage. Which keyword expresses this dependency?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which modern keyword should be used to control whether a job is added to a pipeline based on conditions such as branch name or changed files?$gl$, $gl$[{"id":"a","text":"rules"},{"id":"b","text":"tags"},{"id":"c","text":"environment"},{"id":"d","text":"services"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`rules` is the recommended mechanism to include/exclude jobs conditionally (it supersedes `only`/`except`). `tags` selects runners, `environment` declares a deployment target, and `services` attaches helper containers.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which modern keyword should be used to control whether a job is added to a pipeline based on conditions such as branch name or changed files?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A job specifies `tags: [docker]`. What does this control?$gl$, $gl$[{"id":"a","text":"Which Git tag the job builds from"},{"id":"b","text":"That the job only runs for tagged releases"},{"id":"c","text":"That the job runs only on runners that have the matching `docker` tag"},{"id":"d","text":"The Docker image used to run the job"}]$gl$::jsonb, $gl$["c"]$gl$::jsonb, $gl$Job `tags` are matched against runner tags so the job is picked up only by runners registered with those tags. Git tag pipelines use `rules`/`CI_COMMIT_TAG`; the job's container is set with `image`.$gl$, $gl$[{"url":"https://docs.gitlab.com/runner/","label":"GitLab Docs — GitLab Runner"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job specifies `tags: [docker]`. What does this control?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$In a merge request description or commit message, which phrase automatically closes issue #42 when the change merges to the default branch?$gl$, $gl$[{"id":"a","text":"See #42"},{"id":"b","text":"Closes #42"},{"id":"c","text":"Related to #42"},{"id":"d","text":"Mentions #42"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$GitLab recognizes closing keywords such as `Closes #42` (also Fixes/Resolves) in MR descriptions and commit messages; merging to the default branch closes the referenced issue. "See" / "Related to" only create cross-links.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In a merge request description or commit message, which phrase automatically closes issue #42 when the change merges to the default branch?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$A team wants a Kanban-style view where dragging an issue between columns changes its labels. Which GitLab feature provides this?$gl$, $gl$[{"id":"a","text":"Milestones"},{"id":"b","text":"Issue boards"},{"id":"c","text":"Epics"},{"id":"d","text":"Snippets"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Issue boards present issues in label/list columns; moving a card between lists updates the issue's labels. Milestones group work by time/scope, epics group issues across projects, and snippets store shareable code.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"},{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A team wants a Kanban-style view where dragging an issue between columns changes its labels. Which GitLab feature provides this?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which GitLab object groups multiple related issues that may span several projects into a single higher-level deliverable?$gl$, $gl$[{"id":"a","text":"Label"},{"id":"b","text":"Milestone"},{"id":"c","text":"Epic"},{"id":"d","text":"Tag"}]$gl$::jsonb, $gl$["c"]$gl$::jsonb, $gl$Epics (a group-level feature) collect issues across projects under one initiative. Labels categorize, milestones track a scoped/time-boxed set of work, and Git tags mark commits.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/epics/","label":"GitLab Docs — Epics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which GitLab object groups multiple related issues that may span several projects into a single higher-level deliverable?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which GitLab security scanner analyzes your source code (without executing it) to find potential vulnerabilities?$gl$, $gl$[{"id":"a","text":"SAST (Static Application Security Testing)"},{"id":"b","text":"Dependency Scanning"},{"id":"c","text":"Secret Detection"},{"id":"d","text":"Container Registry"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$SAST inspects source code statically for insecure patterns. Dependency Scanning checks third-party libraries for known CVEs, Secret Detection finds leaked credentials, and the Container Registry stores images (not a scanner).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which GitLab security scanner analyzes your source code (without executing it) to find potential vulnerabilities?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which GitLab default role grants the LEAST privilege — typically read-only visibility into a private project, with no ability to push code?$gl$, $gl$[{"id":"a","text":"Guest"},{"id":"b","text":"Developer"},{"id":"c","text":"Maintainer"},{"id":"d","text":"Owner"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$The role hierarchy is Guest < Reporter < Developer < Maintainer < Owner. Guest is the lowest, with limited read access and no push rights. Developers can push to non-protected branches; Maintainers/Owners administer the project/group.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which GitLab default role grants the LEAST privilege — typically read-only visibility into a private project, with no ability to push code?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which feature records who performed sensitive actions (e.g. permission changes, settings changes) for compliance review?$gl$, $gl$[{"id":"a","text":"Issue boards"},{"id":"b","text":"Audit events"},{"id":"c","text":"CI/CD cache"},{"id":"d","text":"Snippets"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Audit events log security-relevant actions (membership/permission/setting changes) with actor and timestamp, supporting compliance and forensics. Boards, cache, and snippets are unrelated to audit logging.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"},{"url":"https://docs.gitlab.com/ee/administration/compliance.html","label":"GitLab Docs — Compliance"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which feature records who performed sensitive actions (e.g. permission changes, settings changes) for compliance review?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What is the staging area (also called the index) in Git?$gl$, $gl$[{"id":"a","text":"A remote server that mirrors the repository"},{"id":"b","text":"An intermediate area where changes are prepared before they become part of the next commit"},{"id":"c","text":"A backup of every previous commit"},{"id":"d","text":"A temporary branch created during a merge"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The staging area (index) holds the snapshot that will go into the next commit. `git add` moves changes into it, and `git commit` records exactly what is staged. It is local, not a remote or a backup.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the staging area (also called the index) in Git?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which command discards unstaged changes in the tracked file `app.py`, restoring it to the last committed state?$gl$, $gl$[{"id":"a","text":"git restore app.py"},{"id":"b","text":"git rm app.py"},{"id":"c","text":"git stash drop app.py"},{"id":"d","text":"git commit --reset app.py"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git restore app.py` (or the older `git checkout -- app.py`) discards working-tree changes for that file. `git rm` deletes and stages a removal, `git stash drop` removes a stash entry, and `--reset` is not a commit flag.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command discards unstaged changes in the tracked file `app.py`, restoring it to the last committed state?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the `.gitignore` file do?$gl$, $gl$[{"id":"a","text":"Encrypts files before they are committed"},{"id":"b","text":"Specifies intentionally untracked file patterns that Git should not stage or report as untracked"},{"id":"c","text":"Lists files that must always be committed"},{"id":"d","text":"Records the commit history in a human-readable form"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`.gitignore` lists glob patterns for files Git should not track (build output, secrets, dependencies). It does not encrypt, force-include, or store history. Already-tracked files are not affected until untracked.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the `.gitignore` file do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which command shows the commit history of the current branch, most recent first?$gl$, $gl$[{"id":"a","text":"git status"},{"id":"b","text":"git log"},{"id":"c","text":"git reflog --branches"},{"id":"d","text":"git diff HEAD"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git log` lists commits reachable from HEAD, newest first, with author, date, and message. `git status` shows working-tree state, `git diff HEAD` shows changes vs HEAD, and `git reflog` shows ref movements (not the same as branch history).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command shows the commit history of the current branch, most recent first?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A merge produced conflicts. After manually editing the files to resolve them, what completes the merge?$gl$, $gl$[{"id":"a","text":"git merge --abort"},{"id":"b","text":"git add the resolved files, then git commit"},{"id":"c","text":"git reset --hard HEAD"},{"id":"d","text":"git checkout --theirs ."}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$After fixing conflict markers you stage the resolved files with `git add` and then `git commit` to finalize the merge commit. `--abort` cancels the merge, `reset --hard` discards work, and `--theirs` blindly takes one side.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A merge produced conflicts. After manually editing the files to resolve them, what completes the merge?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: A commit SHA in Git is a hash that uniquely identifies the content and history of that commit.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Each commit gets a SHA-1 (or SHA-256) hash computed over its tree, parent(s), author, message, etc. Changing any of those produces a different SHA, which is why rewriting history changes commit IDs.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: A commit SHA in Git is a hash that uniquely identifies the content and history of that commit.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What does `git diff` (with no arguments) show by default?$gl$, $gl$[{"id":"a","text":"The differences between staged changes and the last commit"},{"id":"b","text":"The differences between the working tree and the staging area (unstaged changes)"},{"id":"c","text":"A list of all branches"},{"id":"d","text":"The remote URL configuration"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Plain `git diff` shows unstaged changes — working tree vs index. `git diff --cached` (or `--staged`) shows staged vs last commit. It does not list branches or show remotes.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `git diff` (with no arguments) show by default?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want to undo a pushed commit on a shared branch without rewriting history. Which command is safest?$gl$, $gl$[{"id":"a","text":"git reset --hard HEAD~1 then force push"},{"id":"b","text":"git revert <commit>"},{"id":"c","text":"git rebase -i HEAD~1"},{"id":"d","text":"git commit --amend then force push"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git revert` creates a new commit that undoes the target commit, preserving history — safe for shared branches. The other options rewrite history and require force-pushing, which disrupts collaborators.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want to undo a pushed commit on a shared branch without rewriting history. Which command is safest?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about Git branches.$gl$, $gl$[{"id":"a","text":"A branch is a lightweight movable pointer to a commit."},{"id":"b","text":"Creating a branch copies the entire repository contents to a new directory."},{"id":"c","text":"HEAD normally points to the currently checked-out branch."},{"id":"d","text":"Deleting a merged branch removes the commits it shared with main."}]$gl$::jsonb, $gl$["a","c"]$gl$::jsonb, $gl$A branch is just a movable pointer/ref to a commit, and HEAD references the current branch. Branches are not directory copies, and deleting a branch only removes the label — shared commits reachable from other branches remain.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about Git branches.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is the default branch in a GitLab project typically used for?$gl$, $gl$[{"id":"a","text":"Storing CI/CD logs"},{"id":"b","text":"Serving as the primary, stable line of development that pipelines and merge requests target by default"},{"id":"c","text":"Holding only documentation"},{"id":"d","text":"Running runners"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The default branch (often `main`) is the primary integration branch; new MRs and many pipeline rules target it, and it is commonly protected. It is not a log store or runner.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"},{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the default branch in a GitLab project typically used for?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A CODEOWNERS file in a GitLab repository primarily does what?$gl$, $gl$[{"id":"a","text":"Defines which users/groups are responsible for specific files or paths so they can be required reviewers"},{"id":"b","text":"Lists the project members allowed to clone the repository"},{"id":"c","text":"Configures CI/CD runner tags"},{"id":"d","text":"Sets the project visibility level"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$CODEOWNERS maps file/path patterns to owners; combined with protected branches, owners can be required approvers for changes to their paths. It does not manage cloning, runners, or visibility.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A CODEOWNERS file in a GitLab repository primarily does what?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which statement best describes a merge request in GitLab?$gl$, $gl$[{"id":"a","text":"A request to delete a branch permanently"},{"id":"b","text":"A proposal to merge changes from a source branch into a target branch, with review, discussion, and CI"},{"id":"c","text":"A scheduled backup of the repository"},{"id":"d","text":"A way to fork a project"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A merge request proposes integrating a source branch into a target branch and is the hub for code review, discussion, approvals, and pipeline results. It is not a deletion, backup, or fork operation.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which statement best describes a merge request in GitLab?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Your MR target branch advanced and now has conflicts with your source branch. Which is a valid resolution path entirely within GitLab/Git?$gl$, $gl$[{"id":"a","text":"Close the MR and open a new project"},{"id":"b","text":"Rebase or merge the target branch into your source branch, resolve conflicts, and push the update"},{"id":"c","text":"Delete the target branch"},{"id":"d","text":"Force the MR to merge ignoring conflicts"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$You update the source branch by merging or rebasing the latest target into it, resolving conflicts, then pushing; the MR re-evaluates. GitLab will not merge with unresolved conflicts, and deleting the target is not a resolution.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Your MR target branch advanced and now has conflicts with your source branch. Which is a valid resolution path entirely within GitLab/Git?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL valid GitLab merge methods.$gl$, $gl$[{"id":"a","text":"Merge commit"},{"id":"b","text":"Merge commit with semi-linear history"},{"id":"c","text":"Fast-forward merge"},{"id":"d","text":"Rebase and rename"}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$GitLab supports "Merge commit", "Merge commit with semi-linear history", and "Fast-forward merge". "Rebase and rename" is not a GitLab merge method.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL valid GitLab merge methods.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$In GitLab Flow, what triggers a deployment to an environment in the simplest model?$gl$, $gl$[{"id":"a","text":"Manually copying files to the server"},{"id":"b","text":"Merging into the branch associated with that environment, which runs the deployment pipeline"},{"id":"c","text":"Creating an issue labeled deploy"},{"id":"d","text":"Renaming the repository"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$GitLab Flow ties environments to branches; merging into an environment branch triggers the pipeline that deploys it. Manual file copies or issue labels are not the GitLab Flow deployment mechanism.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"},{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In GitLab Flow, what triggers a deployment to an environment in the simplest model?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which Git command integrates upstream changes into your branch by replaying your commits on top of the latest upstream tip, keeping linear history?$gl$, $gl$[{"id":"a","text":"git merge upstream/main"},{"id":"b","text":"git rebase upstream/main"},{"id":"c","text":"git cherry-pick upstream/main"},{"id":"d","text":"git reset upstream/main"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git rebase upstream/main` reapplies your commits onto the updated base for a linear history. `git merge` creates a merge commit instead; cherry-pick copies specific commits; reset moves the branch pointer.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which Git command integrates upstream changes into your branch by replaying your commits on top of the latest upstream tip, keeping linear history?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which protected-branch setting forces all changes to go through a merge request rather than direct pushes, even for Maintainers?$gl$, $gl$[{"id":"a","text":"Set \"Allowed to push and merge\" to \"No one\" while allowing merge"},{"id":"b","text":"Disable the repository"},{"id":"c","text":"Make the project private"},{"id":"d","text":"Remove all members"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Setting "Allowed to push" to "No one" (while merge is still allowed for some role) forces all changes through MRs since nobody can push directly. Privacy/visibility and membership do not enforce MR-only flow.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which protected-branch setting forces all changes to go through a merge request rather than direct pushes, even for Maintainers?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: In a typical GitLab feature-branch workflow, the feature branch should be kept short-lived and merged back via a merge request after review and passing CI.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Short-lived feature branches reduce merge conflicts and integration risk; they are merged via MR once reviewed and CI is green, keeping the default branch stable.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: In a typical GitLab feature-branch workflow, the feature branch should be kept short-lived and merged back via a merge request after review and passing CI.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$In `.gitlab-ci.yml`, what does the top-level `stages` keyword define?$gl$, $gl$[{"id":"a","text":"The Docker images used by all jobs"},{"id":"b","text":"The ordered list of stages and the order in which groups of jobs execute"},{"id":"c","text":"The runners assigned to the project"},{"id":"d","text":"The environment variables for the pipeline"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`stages` lists the pipeline stages in execution order; jobs are assigned to a stage and stages run sequentially while jobs within a stage run in parallel. It does not set images, runners, or variables.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In `.gitlab-ci.yml`, what does the top-level `stages` keyword define?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the `script` keyword in a job specify?$gl$, $gl$[{"id":"a","text":"The runner tags"},{"id":"b","text":"The shell commands the runner executes for that job"},{"id":"c","text":"The artifacts to upload"},{"id":"d","text":"The stage name"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`script` is the required list of shell commands a job runs. `tags` selects runners, `artifacts` declares outputs, and `stage` assigns the job to a stage.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the `script` keyword in a job specify?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which keyword sets commands that run before the main `script` in a job (e.g. installing dependencies)?$gl$, $gl$[{"id":"a","text":"before_script"},{"id":"b","text":"pre_run"},{"id":"c","text":"setup"},{"id":"d","text":"init"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`before_script` runs prior to `script` (and `after_script` runs afterward, even on failure). `pre_run`, `setup`, and `init` are not GitLab CI keywords.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword sets commands that run before the main `script` in a job (e.g. installing dependencies)?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the `image` keyword specify for a job using the Docker executor?$gl$, $gl$[{"id":"a","text":"The Git branch to build"},{"id":"b","text":"The Docker image used as the environment in which the job runs"},{"id":"c","text":"The artifact name"},{"id":"d","text":"The runner host operating system"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`image` sets the container image the job runs inside (with the Docker executor). It is unrelated to branches, artifact naming, or directly choosing the runner host OS.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the `image` keyword specify for a job using the Docker executor?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want a job to run only when files under `src/` change. Which configuration expresses this?$gl$, $gl$[{"id":"a","text":"rules: - changes: [\"src/**/*\"]"},{"id":"b","text":"only: branches"},{"id":"c","text":"needs: [src]"},{"id":"d","text":"environment: src"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`rules:changes` includes the job only when the listed paths change. `only: branches` is unrelated to file changes, `needs` builds a DAG, and `environment` declares a deployment target.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want a job to run only when files under `src/` change. Which configuration expresses this?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A job sets `retry: 2`. What is the effect?$gl$, $gl$[{"id":"a","text":"The job runs twice in parallel"},{"id":"b","text":"If the job fails, GitLab automatically retries it up to two more times"},{"id":"c","text":"The job is delayed by two minutes"},{"id":"d","text":"The pipeline retries from the first stage"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`retry: 2` makes GitLab automatically re-run a failed job up to two additional times before marking it failed. It does not parallelize, delay, or restart the whole pipeline.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job sets `retry: 2`. What is the effect?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `when: on_failure` on a job mean?$gl$, $gl$[{"id":"a","text":"The job runs only if a job in an earlier stage failed"},{"id":"b","text":"The job always runs"},{"id":"c","text":"The job never runs"},{"id":"d","text":"The job runs only on protected branches"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`when: on_failure` runs the job only when at least one job in an earlier stage failed (useful for cleanup/notifications). `on_success` (default), `always`, and `manual` are the other common values.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `when: on_failure` on a job mean?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about pipeline triggers/types in GitLab.$gl$, $gl$[{"id":"a","text":"A branch pipeline runs when commits are pushed to a branch."},{"id":"b","text":"A merge request pipeline can run for changes proposed in an MR."},{"id":"c","text":"A scheduled pipeline runs on a defined cron-like schedule."},{"id":"d","text":"Pipelines can only ever be started manually by an administrator."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$GitLab supports branch, merge request, scheduled, tag, and manually-triggered pipelines, among others. Pipelines are NOT restricted to admin-only manual starts.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about pipeline triggers/types in GitLab.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which predefined CI/CD variable holds the branch or tag name for which the pipeline is running?$gl$, $gl$[{"id":"a","text":"CI_PROJECT_DIR"},{"id":"b","text":"CI_COMMIT_REF_NAME"},{"id":"c","text":"CI_RUNNER_ID"},{"id":"d","text":"CI_JOB_STAGE"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`CI_COMMIT_REF_NAME` is the branch or tag the pipeline runs for. `CI_PROJECT_DIR` is the checkout path, `CI_JOB_STAGE` the stage name, and `CI_RUNNER_ID` the runner identifier.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which predefined CI/CD variable holds the branch or tag name for which the pipeline is running?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$What is the purpose of the `cache:key` keyword?$gl$, $gl$[{"id":"a","text":"It encrypts the cache contents"},{"id":"b","text":"It defines a key that determines which cache is reused/stored, enabling per-branch or per-dependency caches"},{"id":"c","text":"It selects which runner stores the cache"},{"id":"d","text":"It sets the artifact expiry"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`cache:key` controls cache identity (e.g. keyed by branch or a lockfile hash) so the right cache is restored/saved. It does not encrypt, choose runners, or set artifact expiry.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the purpose of the `cache:key` keyword?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 4, $gl$SINGLE$gl$::"QType", $gl$A deploy job has `environment: name: production` and `when: manual`. What is the typical reason for this combination?$gl$, $gl$[{"id":"a","text":"To deploy automatically on every commit"},{"id":"b","text":"To require a human to explicitly trigger the production deployment (a manual gate)"},{"id":"c","text":"To disable deployments"},{"id":"d","text":"To run the job on every branch"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Combining `environment` with `when: manual` creates a tracked production deployment that a person must click to run — a deliberate release gate. It is the opposite of automatic on every commit.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A deploy job has `environment: name: production` and `when: manual`. What is the typical reason for this combination?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 4, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about GitLab Runners and executors.$gl$, $gl$[{"id":"a","text":"Runners can be instance-wide (shared), group, or project-specific."},{"id":"b","text":"The docker executor isolates each job in a container."},{"id":"c","text":"A runner must always use the shell executor."},{"id":"d","text":"Job tags are matched to runner tags to route jobs."}]$gl$::jsonb, $gl$["a","b","d"]$gl$::jsonb, $gl$Runners can be shared/group/project-scoped, the docker executor isolates jobs per container, and job tags route work to tagged runners. A runner is NOT forced to use the shell executor — many executors exist (docker, kubernetes, shell, ssh, etc.).$gl$, $gl$[{"url":"https://docs.gitlab.com/runner/","label":"GitLab Docs — GitLab Runner"},{"url":"https://docs.gitlab.com/runner/executors/","label":"GitLab Docs — Runner executors"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about GitLab Runners and executors.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$To authenticate a CI/CD job pushing an image to the project Container Registry, which predefined variables are most relevant?$gl$, $gl$[{"id":"a","text":"CI_REGISTRY, CI_REGISTRY_USER, CI_REGISTRY_PASSWORD"},{"id":"b","text":"CI_PAGES_URL only"},{"id":"c","text":"CI_RUNNER_TAGS"},{"id":"d","text":"CI_DEFAULT_BRANCH"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$GitLab injects `CI_REGISTRY`, `CI_REGISTRY_USER`, and `CI_REGISTRY_PASSWORD` (and `CI_REGISTRY_IMAGE`) so jobs can `docker login` and push to the integrated registry. The others are unrelated to registry auth.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/packages/container_registry/","label":"GitLab Docs — Container Registry"},{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$To authenticate a CI/CD job pushing an image to the project Container Registry, which predefined variables are most relevant?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What is a GitLab issue primarily used for?$gl$, $gl$[{"id":"a","text":"Storing compiled binaries"},{"id":"b","text":"Tracking work such as bugs, feature requests, and tasks, with discussion and assignment"},{"id":"c","text":"Running CI/CD pipelines"},{"id":"d","text":"Hosting a static website"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Issues track and discuss work items (bugs, features, tasks) with assignees, labels, milestones, and threaded comments. Binaries go to artifacts/registry, pipelines run CI, and Pages hosts sites.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is a GitLab issue primarily used for?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which feature lets you assign an issue or merge request to a specific person responsible for it?$gl$, $gl$[{"id":"a","text":"Assignees"},{"id":"b","text":"Labels"},{"id":"c","text":"Tags"},{"id":"d","text":"Runners"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Assignees designate who is responsible for an issue/MR (GitLab also supports multiple assignees in some tiers). Labels categorize, Git tags mark commits, and runners execute CI.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which feature lets you assign an issue or merge request to a specific person responsible for it?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does referencing `!123` in an issue comment do?$gl$, $gl$[{"id":"a","text":"Deletes merge request 123"},{"id":"b","text":"Creates a cross-link to merge request number 123"},{"id":"c","text":"Merges MR 123 immediately"},{"id":"d","text":"Assigns the issue to user 123"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$GitLab reference syntax: `#123` links an issue, `!123` links a merge request, `@user` mentions a user. It creates a navigable cross-reference, not a destructive action.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does referencing `!123` in an issue comment do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which feature visualizes remaining work over time for a milestone?$gl$, $gl$[{"id":"a","text":"Burndown chart"},{"id":"b","text":"Container registry"},{"id":"c","text":"CI/CD cache"},{"id":"d","text":"Protected branch"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$A burndown (and burnup) chart on a milestone shows progress/remaining work over the milestone period. The registry, cache, and protected branches are unrelated to milestone progress visualization.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which feature visualizes remaining work over time for a milestone?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about labels in GitLab.$gl$, $gl$[{"id":"a","text":"Labels can be project-scoped or group-scoped."},{"id":"b","text":"Scoped labels (key::value) enforce mutual exclusivity within a scope."},{"id":"c","text":"Labels can be used to build issue board lists."},{"id":"d","text":"A label can only ever be applied to one issue at a time."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Labels can be project or group level, scoped labels (`key::value`) are mutually exclusive within their key, and board lists are built from labels. A label can be applied to many issues — it is not single-use.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"},{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about labels in GitLab.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Two issues must be done in order — issue B should not start until A is finished. Which GitLab capability models this dependency?$gl$, $gl$[{"id":"a","text":"Linked issues with a \"blocks/is blocked by\" relationship"},{"id":"b","text":"A shared label only"},{"id":"c","text":"A protected tag"},{"id":"d","text":"A CI/CD cache"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$GitLab linked issues support relationship types including "blocks" / "is blocked by", explicitly modeling ordering dependencies. Labels alone do not enforce a dependency, and tags/cache are unrelated.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Two issues must be done in order — issue B should not start until A is finished. Which GitLab capability models this dependency?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What is a GitLab Wiki used for?$gl$, $gl$[{"id":"a","text":"Running CI/CD jobs"},{"id":"b","text":"Maintaining project documentation in a versioned, separate Git repository"},{"id":"c","text":"Storing Docker images"},{"id":"d","text":"Tracking commit SHAs"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A project Wiki holds documentation, backed by its own Git repository and versioned independently of the code. It does not run CI, store images, or track commit hashes.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is a GitLab Wiki used for?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Order the GitLab default roles from least to most privileged.$gl$, $gl$[{"id":"a","text":"Owner < Maintainer < Developer < Reporter < Guest"},{"id":"b","text":"Guest < Reporter < Developer < Maintainer < Owner"},{"id":"c","text":"Reporter < Guest < Maintainer < Developer < Owner"},{"id":"d","text":"Developer < Guest < Reporter < Maintainer < Owner"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The default role hierarchy is Guest < Reporter < Developer < Maintainer < Owner, with each level adding capabilities (Reporter adds read of issues/code analytics, Developer adds push, etc.).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Order the GitLab default roles from least to most privileged.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which role can typically view issues and the repository but cannot push code or create merge requests?$gl$, $gl$[{"id":"a","text":"Owner"},{"id":"b","text":"Maintainer"},{"id":"c","text":"Reporter"},{"id":"d","text":"Developer"}]$gl$::jsonb, $gl$["c"]$gl$::jsonb, $gl$Reporter has read-oriented access (view code, issues, analytics) but no push or MR-create rights. Developers can push and open MRs; Maintainers/Owners administer the project.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which role can typically view issues and the repository but cannot push code or create merge requests?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$How are GitLab SAST results most commonly surfaced to reviewers?$gl$, $gl$[{"id":"a","text":"As emails only"},{"id":"b","text":"In the merge request security widget and the pipeline Security tab, showing newly introduced vulnerabilities"},{"id":"c","text":"Only in the project README"},{"id":"d","text":"In the container registry"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$SAST (and other scanners) report findings into the pipeline Security tab and the MR security widget, highlighting vulnerabilities introduced by the change so reviewers can act before merging.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$How are GitLab SAST results most commonly surfaced to reviewers?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL GitLab application security scanning categories.$gl$, $gl$[{"id":"a","text":"SAST (static analysis of source code)"},{"id":"b","text":"Secret Detection (finding leaked credentials)"},{"id":"c","text":"Dependency Scanning (known CVEs in dependencies)"},{"id":"d","text":"Branch Renaming Scanning"}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$SAST, Secret Detection, and Dependency Scanning are real GitLab security scanning categories (alongside DAST, container scanning, etc.). "Branch Renaming Scanning" is not a security scanner.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"},{"url":"https://docs.gitlab.com/ee/user/application_security/dependency_scanning/","label":"GitLab Docs — Dependency scanning"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL GitLab application security scanning categories.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A leaked API token was committed last week. Which scanner is designed to detect it, and what is the recommended remediation?$gl$, $gl$[{"id":"a","text":"Dependency Scanning; ignore it"},{"id":"b","text":"Secret Detection; revoke/rotate the token and remove it from the codebase"},{"id":"c","text":"SAST; just delete the file"},{"id":"d","text":"Container Scanning; rebuild the image only"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Secret Detection flags committed credentials. Because Git history retains the secret, the correct response is to revoke/rotate the token immediately and remove it from code/config (deleting the file alone is insufficient).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A leaked API token was committed last week. Which scanner is designed to detect it, and what is the recommended remediation?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Why should secrets (passwords, tokens) be stored as masked/protected CI/CD variables rather than committed to the repository?$gl$, $gl$[{"id":"a","text":"It makes pipelines run faster"},{"id":"b","text":"It keeps secrets out of version history and reduces exposure in logs and to untrusted branches"},{"id":"c","text":"It is required to use any runner"},{"id":"d","text":"It automatically encrypts the whole repository"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Storing secrets as masked/protected CI/CD variables avoids persisting them in Git history, hides them in job logs, and limits exposure to protected refs — far safer than committing them. It is not a speed or runner requirement.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Why should secrets (passwords, tokens) be stored as masked/protected CI/CD variables rather than committed to the repository?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: Making a project "private" in GitLab restricts access so only explicitly added members can view it.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Private visibility means only project members (or group members with inherited access) can see the project. Internal is logged-in users; public is anyone.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"},{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P1$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: Making a project "private" in GitLab restricts access so only explicitly added members can view it.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$Which command creates a new branch named `feature-x` and immediately switches to it?$gl$, $gl$[{"id":"a","text":"git branch feature-x"},{"id":"b","text":"git checkout -b feature-x"},{"id":"c","text":"git switch feature-x"},{"id":"d","text":"git merge feature-x"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git checkout -b feature-x` creates and checks out the branch in one step (equivalent to `git switch -c feature-x`). `git branch feature-x` creates it without switching, and `git switch feature-x` fails if the branch does not exist.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command creates a new branch named `feature-x` and immediately switches to it?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `git merge feature` do when run while `main` is checked out and the branches have diverged?$gl$, $gl$[{"id":"a","text":"Deletes the feature branch after copying its files"},{"id":"b","text":"Combines the histories of feature into main, creating a merge commit when needed"},{"id":"c","text":"Rewrites main's history to match feature exactly"},{"id":"d","text":"Pushes feature to the remote main branch"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Merging integrates the feature branch into main; with diverged history Git creates a merge commit with two parents. It does not delete branches, rewrite history (that is rebase), or push anything.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `git merge feature` do when run while `main` is checked out and the branches have diverged?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: `git fetch` updates your remote-tracking branches but does NOT modify your local working branch or files.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. `git fetch` downloads new objects and updates remote-tracking refs (e.g. `origin/main`) but leaves your checked-out branch untouched. `git pull` is `fetch` followed by a merge/rebase, which does change your working branch.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: `git fetch` updates your remote-tracking branches but does NOT modify your local working branch or files.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You accidentally ran `git stash` twice. Which command lists all stash entries so you can choose which to restore?$gl$, $gl$[{"id":"a","text":"git stash show"},{"id":"b","text":"git stash list"},{"id":"c","text":"git stash pop --all"},{"id":"d","text":"git log --stash"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git stash list` shows the stack of stash entries (stash@{0}, stash@{1}, ...). `git stash show` displays one entry's diff, and there is no `--all` flag on pop or a `--stash` option on log.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/stash.html","label":"GitLab Docs — Git stash"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You accidentally ran `git stash` twice. Which command lists all stash entries so you can choose which to restore?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Within a GitLab group, what is a subgroup primarily used for?$gl$, $gl$[{"id":"a","text":"Storing CI/CD job logs separately from projects"},{"id":"b","text":"Organizing projects and members into a nested hierarchy under the parent group"},{"id":"c","text":"Replacing protected branches at the instance level"},{"id":"d","text":"Running pipelines without a runner"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Subgroups create a nested namespace hierarchy, letting you mirror team/department structure and inherit/scope membership and settings. They are not log storage, branch protection, or a runner substitute.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"},{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Within a GitLab group, what is a subgroup primarily used for?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about protected branches in GitLab.$gl$, $gl$[{"id":"a","text":"You can configure which roles are allowed to push and which are allowed to merge."},{"id":"b","text":"Force push to a protected branch is blocked by default."},{"id":"c","text":"Protected branches make the repository read-only for everyone."},{"id":"d","text":"You can require code owner approval on a protected branch."}]$gl$::jsonb, $gl$["a","b","d"]$gl$::jsonb, $gl$Protected branches let you set allowed push/merge roles, block force pushes by default, and optionally require Code Owner approval. They do NOT make the whole repository read-only — only the protected branch is restricted.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about protected branches in GitLab.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$After forking a project, how do you keep your fork up to date with new commits on the original (upstream) project?$gl$, $gl$[{"id":"a","text":"Delete and re-fork every time upstream changes"},{"id":"b","text":"Add the original project as a remote (e.g. upstream) and fetch/merge its changes into your fork"},{"id":"c","text":"Open an issue asking maintainers to sync your fork"},{"id":"d","text":"Forks update automatically and require no action ever"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$You add the original repo as a second remote (commonly `upstream`), then fetch and merge/rebase its changes into your fork. GitLab also offers a UI "Update fork" action, but forks do not sync fully automatically.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$After forking a project, how do you keep your fork up to date with new commits on the original (upstream) project?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$In GitLab Flow with environment branches, how is code typically promoted from staging to production?$gl$, $gl$[{"id":"a","text":"By force-pushing the staging branch over production"},{"id":"b","text":"By merging the production-ready branch into the production environment branch (often via merge request)"},{"id":"c","text":"By committing directly to the production branch on the server"},{"id":"d","text":"By deleting the staging branch"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$GitLab Flow promotes changes forward by merging into downstream environment branches (e.g. main → pre-production → production), typically through merge requests so review/CI gate each promotion. Force-pushing or direct server commits bypass that flow.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In GitLab Flow with environment branches, how is code typically promoted from staging to production?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$A job sets `when: manual`. What is the effect?$gl$, $gl$[{"id":"a","text":"The job runs automatically but with low priority"},{"id":"b","text":"The job is added to the pipeline but only runs when a user explicitly triggers (plays) it"},{"id":"c","text":"The job is skipped entirely"},{"id":"d","text":"The job runs only on manual (self-managed) runners"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`when: manual` creates a job that appears in the pipeline but stays paused until a user clicks play. It is commonly used for deployments. It is unrelated to runner type or priority.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job sets `when: manual`. What is the effect?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$A job has `allow_failure: true` and it fails. What happens to the pipeline?$gl$, $gl$[{"id":"a","text":"The pipeline fails immediately"},{"id":"b","text":"The pipeline continues and is not marked as failed because of this job (it shows a warning)"},{"id":"c","text":"The job is automatically retried three times"},{"id":"d","text":"The next stage is skipped"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`allow_failure: true` lets a job fail without failing the pipeline; the pipeline proceeds and shows a warning indicator. It does not trigger retries or skip stages.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job has `allow_failure: true` and it fails. What happens to the pipeline?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want to reuse a shared pipeline template stored in another repository. Which `.gitlab-ci.yml` keyword references external configuration?$gl$, $gl$[{"id":"a","text":"extends"},{"id":"b","text":"include"},{"id":"c","text":"needs"},{"id":"d","text":"trigger"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`include` pulls in external YAML (local file, another project, remote URL, or a template). `extends` reuses configuration defined within the same file, `needs` builds a DAG, and `trigger` starts downstream pipelines.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/includes.html","label":"GitLab Docs — include"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want to reuse a shared pipeline template stored in another repository. Which `.gitlab-ci.yml` keyword references external configuration?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about CI/CD variables in GitLab.$gl$, $gl$[{"id":"a","text":"Project-level CI/CD variables can be marked \"masked\" so their values are hidden in job logs."},{"id":"b","text":"Variables can be marked \"protected\" so they are only available on protected branches and tags."},{"id":"c","text":"Predefined variables like CI_COMMIT_REF_NAME are provided automatically by GitLab."},{"id":"d","text":"CI/CD variables can only be defined inside the .gitlab-ci.yml file."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Variables can be masked, marked protected, and GitLab injects many predefined variables (e.g. `CI_COMMIT_REF_NAME`). They can be defined in the YAML file OR in project/group/instance settings — not only in the file.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about CI/CD variables in GitLab.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A `deploy` job defines `environment: name: production, url: https://example.com`. What does declaring an environment provide?$gl$, $gl$[{"id":"a","text":"It encrypts all artifacts produced by the job"},{"id":"b","text":"It tracks deployments to that environment and enables features like deployment history and rollback"},{"id":"c","text":"It forces the job to run on a shared runner"},{"id":"d","text":"It disables the job's logs for security"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Declaring an `environment` lets GitLab record deployments, show deployment history, link the live URL, and support rollback/stop actions. It does not affect artifact encryption, runner selection, or log visibility.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A `deploy` job defines `environment: name: production, url: https://example.com`. What does declaring an environment provide?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 4, $gl$SINGLE$gl$::"QType", $gl$Which runner executor runs each CI/CD job in its own container, giving clean isolated environments per job?$gl$, $gl$[{"id":"a","text":"shell"},{"id":"b","text":"docker"},{"id":"c","text":"ssh"},{"id":"d","text":"static"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The `docker` executor spins up a fresh container per job, providing isolation and reproducibility. The `shell` executor runs jobs directly on the runner host (shared state), `ssh` runs them on a remote machine, and `static` is not a GitLab Runner executor.$gl$, $gl$[{"url":"https://docs.gitlab.com/runner/executors/","label":"GitLab Docs — Runner executors"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which runner executor runs each CI/CD job in its own container, giving clean isolated environments per job?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is the purpose of marking a merge request as a Draft (e.g. title prefixed with "Draft:")?$gl$, $gl$[{"id":"a","text":"It permanently deletes the source branch"},{"id":"b","text":"It signals the MR is not ready and blocks merging until the Draft flag is removed"},{"id":"c","text":"It automatically approves the merge request"},{"id":"d","text":"It converts the MR into an issue"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A Draft MR communicates work-in-progress and GitLab prevents it from being merged until the Draft status is cleared. It does not delete branches, auto-approve, or convert to an issue.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/drafts.html","label":"GitLab Docs — Draft merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the purpose of marking a merge request as a Draft (e.g. title prefixed with "Draft:")?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$You want to track all issues and merge requests targeted for the "2.0 Release" with a due date. Which feature fits best?$gl$, $gl$[{"id":"a","text":"A label named release-2.0"},{"id":"b","text":"A milestone named 2.0 Release with a due date"},{"id":"c","text":"A protected tag"},{"id":"d","text":"A snippet"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Milestones group issues/MRs toward a deliverable and support start/due dates and progress burndown. A label only categorizes (no dates), a protected tag marks a commit, and a snippet stores code.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want to track all issues and merge requests targeted for the "2.0 Release" with a due date. Which feature fits best?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$In a merge request, which mechanism lets reviewers formally signal that required approval criteria are met before merging?$gl$, $gl$[{"id":"a","text":"Adding a comment that says \"LGTM\""},{"id":"b","text":"Merge request approvals (approval rules / required approvers)"},{"id":"c","text":"Closing the related issue"},{"id":"d","text":"Adding a label named approved"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Merge request approval rules require a configured number/group of approvers to approve before the MR can merge. A comment or a label is informal and not enforced; closing an issue is unrelated.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In a merge request, which mechanism lets reviewers formally signal that required approval criteria are met before merging?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which GitLab scanner specifically looks for credentials (API keys, tokens, passwords) accidentally committed to the repository?$gl$, $gl$[{"id":"a","text":"Secret Detection"},{"id":"b","text":"SAST"},{"id":"c","text":"Dependency Scanning"},{"id":"d","text":"GitLab Pages"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Secret Detection scans commits/history for leaked secrets like tokens and keys. SAST analyzes code logic, Dependency Scanning checks libraries for known CVEs, and GitLab Pages is static-site hosting.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which GitLab scanner specifically looks for credentials (API keys, tokens, passwords) accidentally committed to the repository?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A user must be able to push to non-protected branches and create merge requests, but should NOT manage project settings or members. Which default role is appropriate?$gl$, $gl$[{"id":"a","text":"Guest"},{"id":"b","text":"Reporter"},{"id":"c","text":"Developer"},{"id":"d","text":"Owner"}]$gl$::jsonb, $gl$["c"]$gl$::jsonb, $gl$The Developer role can push to non-protected branches and create MRs but cannot administer project settings/members. Guest/Reporter cannot push code, and Owner has full administrative control.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A user must be able to push to non-protected branches and create merge requests, but should NOT manage project settings or members. Which default role is appropriate?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which scanner flags third-party libraries declared in your project that have known published vulnerabilities (CVEs)?$gl$, $gl$[{"id":"a","text":"Secret Detection"},{"id":"b","text":"Dependency Scanning"},{"id":"c","text":"SAST"},{"id":"d","text":"Container Registry cleanup policy"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Dependency Scanning analyzes your declared dependencies against vulnerability databases to surface known CVEs. Secret Detection finds leaked credentials, SAST inspects your own code, and a registry cleanup policy only prunes old images.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/dependency_scanning/","label":"GitLab Docs — Dependency scanning"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which scanner flags third-party libraries declared in your project that have known published vulnerabilities (CVEs)?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$Which command initializes a brand-new, empty Git repository in the current directory?$gl$, $gl$[{"id":"a","text":"git init"},{"id":"b","text":"git start"},{"id":"c","text":"git create"},{"id":"d","text":"git new"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git init` creates a new `.git` directory, turning the current folder into a Git repository. `git start`, `git create`, and `git new` are not Git commands.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command initializes a brand-new, empty Git repository in the current directory?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want to apply a single commit from another branch onto your current branch. Which command do you use?$gl$, $gl$[{"id":"a","text":"git merge <commit>"},{"id":"b","text":"git cherry-pick <commit>"},{"id":"c","text":"git rebase <commit>"},{"id":"d","text":"git stash <commit>"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git cherry-pick <commit>` applies the changes of one specific commit onto the current branch as a new commit. Merge integrates whole branches, rebase replays a range, and stash is unrelated.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want to apply a single commit from another branch onto your current branch. Which command do you use?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which command stages all modified and new files in the current directory tree?$gl$, $gl$[{"id":"a","text":"git add ."},{"id":"b","text":"git stage --commit"},{"id":"c","text":"git commit -all"},{"id":"d","text":"git push ."}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git add .` stages changes (including new files) under the current path. `git add -A` stages across the whole repo including deletions. The other forms are not valid Git syntax.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command stages all modified and new files in the current directory tree?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `git clone --branch develop <url>` do?$gl$, $gl$[{"id":"a","text":"Clones the repository and checks out the develop branch"},{"id":"b","text":"Deletes the develop branch on the remote"},{"id":"c","text":"Creates a new branch called develop locally only"},{"id":"d","text":"Clones only the develop file"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git clone --branch develop <url>` clones the repo and checks out `develop` instead of the default branch. It does not delete remote branches or clone a single file.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `git clone --branch develop <url>` do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: `git commit` records a snapshot of only the changes that were added to the staging area.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. A commit captures the staged (indexed) content. Modifications not added to the index are not part of the commit (unless `-a` is used to auto-stage tracked files).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: `git commit` records a snapshot of only the changes that were added to the staging area.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You deleted a local branch that had unmerged commits. Which command can help you find those lost commits?$gl$, $gl$[{"id":"a","text":"git status"},{"id":"b","text":"git reflog"},{"id":"c","text":"git diff"},{"id":"d","text":"git remote -v"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git reflog` records where HEAD and branch refs have pointed, letting you recover commit SHAs from a deleted branch and recreate it. `status`, `diff`, and `remote -v` do not show ref history.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You deleted a local branch that had unmerged commits. Which command can help you find those lost commits?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$In Git, what is HEAD?$gl$, $gl$[{"id":"a","text":"The oldest commit in the repository"},{"id":"b","text":"A reference to the current commit/branch you have checked out"},{"id":"c","text":"The remote server name"},{"id":"d","text":"The staging area"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$HEAD is a symbolic reference to the currently checked-out branch (or commit in detached state). It is not the first commit, a remote name, or the index.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In Git, what is HEAD?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which command lists all local branches and marks the current one with an asterisk?$gl$, $gl$[{"id":"a","text":"git branch"},{"id":"b","text":"git branch -r"},{"id":"c","text":"git log --branches"},{"id":"d","text":"git checkout"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git branch` lists local branches, marking the active one with `*`. `git branch -r` lists remote-tracking branches, and the others do not list local branches that way.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command lists all local branches and marks the current one with an asterisk?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements comparing merge and rebase.$gl$, $gl$[{"id":"a","text":"Merge preserves the original branch history and adds a merge commit when histories diverge."},{"id":"b","text":"Rebase rewrites commits onto a new base, producing a linear history."},{"id":"c","text":"Rebasing a shared/published branch is generally discouraged."},{"id":"d","text":"Merge always rewrites commit SHAs of the feature branch."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Merge keeps both histories (often via a merge commit), rebase replays commits for a linear history, and rebasing shared branches is discouraged because it rewrites history. Merge does NOT rewrite the feature branch's commit SHAs.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"},{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements comparing merge and rebase.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the source branch of a merge request refer to?$gl$, $gl$[{"id":"a","text":"The branch whose changes are proposed to be merged into the target branch"},{"id":"b","text":"The default branch only"},{"id":"c","text":"The branch the changes will be merged into"},{"id":"d","text":"A read-only mirror branch"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$In an MR the source branch contains the changes you want merged; the target branch is where they will land. The source need not be the default branch.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the source branch of a merge request refer to?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A maintainer enabled "Fast-forward merge" only. What must be true for an MR to merge?$gl$, $gl$[{"id":"a","text":"The MR can always merge regardless of history"},{"id":"b","text":"The source branch must be rebased on the latest target so a linear fast-forward is possible"},{"id":"c","text":"A merge commit will be created automatically"},{"id":"d","text":"The target branch must be deleted first"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Fast-forward-only merges require the source to be directly ahead of the target (no merge commit). If the target moved, you must rebase/update the source first. No merge commit is created.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"},{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A maintainer enabled "Fast-forward merge" only. What must be true for an MR to merge?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which is a benefit of keeping feature branches short-lived in GitLab Flow?$gl$, $gl$[{"id":"a","text":"It guarantees no code review is needed"},{"id":"b","text":"It reduces merge conflicts and integration risk by merging small changes frequently"},{"id":"c","text":"It removes the need for CI/CD"},{"id":"d","text":"It prevents the main branch from being protected"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Short-lived branches integrate small changes often, minimizing divergence and conflicts. Review and CI are still required, and main remains protectable.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which is a benefit of keeping feature branches short-lived in GitLab Flow?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about GitLab groups and subgroups.$gl$, $gl$[{"id":"a","text":"A subgroup inherits members and permissions from its parent group."},{"id":"b","text":"Projects can be moved between groups (transferred)."},{"id":"c","text":"A group can contain both projects and subgroups."},{"id":"d","text":"Subgroups cannot have their own members beyond inherited ones."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Subgroups inherit parent membership, projects can be transferred between namespaces, and a group can hold projects and subgroups. Subgroups CAN also have their own additional members, not only inherited ones.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"},{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about GitLab groups and subgroups.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is the target branch of a typical feature merge request?$gl$, $gl$[{"id":"a","text":"Always a tag"},{"id":"b","text":"Usually the default/integration branch (e.g. main) the feature should land in"},{"id":"c","text":"The runner"},{"id":"d","text":"The container registry"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A feature MR usually targets the default integration branch (commonly `main`) where reviewed work is integrated. Tags, runners, and the registry are not MR targets.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the target branch of a typical feature merge request?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$How can you require that specific people review changes to files in `/infra/` before merge?$gl$, $gl$[{"id":"a","text":"Add a label named infra"},{"id":"b","text":"Define CODEOWNERS entries for /infra/ and enable code owner approval on the protected branch"},{"id":"c","text":"Delete the /infra/ directory"},{"id":"d","text":"Disable merge requests"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$CODEOWNERS maps `/infra/` to owners; enabling "Require code owner approval" on the protected target branch forces those owners to approve MRs touching that path. Labels do not enforce reviewers.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$How can you require that specific people review changes to files in `/infra/` before merge?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which statement about forking is correct?$gl$, $gl$[{"id":"a","text":"A fork shares the same storage as the upstream project, so changes affect upstream immediately"},{"id":"b","text":"A fork is an independent server-side copy; you push to it and propose changes upstream via merge requests"},{"id":"c","text":"Forking automatically grants you Owner on upstream"},{"id":"d","text":"You cannot open a merge request from a fork"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A fork is a separate copy you control; changes do not affect upstream until merged via an MR from the fork. Forking does not grant upstream roles, and MRs from forks are fully supported.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which statement about forking is correct?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$In a release-branch GitLab Flow, what is a release branch typically used for?$gl$, $gl$[{"id":"a","text":"Daily feature development"},{"id":"b","text":"Stabilizing a specific release and applying only bug fixes/cherry-picks before tagging"},{"id":"c","text":"Storing CI logs"},{"id":"d","text":"Hosting documentation"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Release branches isolate a version for stabilization: only fixes (often cherry-picked from main) go in before tagging the release. Active feature work continues on main, not the release branch.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In a release-branch GitLab Flow, what is a release branch typically used for?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does "rebase" do to an MR's source branch in GitLab when you click the Rebase button?$gl$, $gl$[{"id":"a","text":"Squashes all commits into one"},{"id":"b","text":"Replays the source branch commits on top of the latest target branch"},{"id":"c","text":"Deletes the source branch"},{"id":"d","text":"Merges the MR immediately"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The Rebase action replays the source branch onto the current tip of the target branch, updating it without a merge commit. It does not squash, delete the branch, or merge.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does "rebase" do to an MR's source branch in GitLab when you click the Rebase button?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What is a "job" in a GitLab CI/CD pipeline?$gl$, $gl$[{"id":"a","text":"A protected branch"},{"id":"b","text":"A defined unit of work (with a script) that a runner executes as part of a stage"},{"id":"c","text":"A merge request"},{"id":"d","text":"A container registry image"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A job is the smallest pipeline unit: it has a script, belongs to a stage, and is run by a runner. It is not a branch, MR, or image.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"},{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is a "job" in a GitLab CI/CD pipeline?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$If no `stages` are defined in `.gitlab-ci.yml`, what default stages does GitLab use?$gl$, $gl$[{"id":"a","text":"build, test, deploy"},{"id":"b","text":"compile, package, ship"},{"id":"c","text":"init, run, end"},{"id":"d","text":"There are no default stages; the pipeline fails"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$When `stages` is omitted, GitLab uses the default `.pre`, `build`, `test`, `deploy`, `.post` ordering (commonly summarized as build → test → deploy). The pipeline does not fail for omitting `stages`.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$If no `stages` are defined in `.gitlab-ci.yml`, what default stages does GitLab use?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which keyword assigns a job to a particular stage?$gl$, $gl$[{"id":"a","text":"stage"},{"id":"b","text":"phase"},{"id":"c","text":"step"},{"id":"d","text":"group"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$The `stage` keyword places a job in a named stage (must exist in `stages` or be a default). `phase`, `step`, and `group` are not GitLab CI keywords for this.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"},{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword assigns a job to a particular stage?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want a job to run for tag pipelines only. Which rule condition matches?$gl$, $gl$[{"id":"a","text":"rules: - if: $CI_COMMIT_TAG"},{"id":"b","text":"rules: - if: $CI_MERGE_REQUEST_IID"},{"id":"c","text":"only: branches"},{"id":"d","text":"when: never"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`$CI_COMMIT_TAG` is set only for tag pipelines, so `rules: - if: $CI_COMMIT_TAG` includes the job for tags. The MR variable matches MR pipelines, `only: branches` excludes tags, and `when: never` disables the job.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"},{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want a job to run for tag pipelines only. Which rule condition matches?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL valid values for a job's `when` keyword.$gl$, $gl$[{"id":"a","text":"on_success"},{"id":"b","text":"manual"},{"id":"c","text":"always"},{"id":"d","text":"random"}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Valid `when` values include `on_success` (default), `on_failure`, `always`, `manual`, `delayed`, and `never`. `random` is not a valid value.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL valid values for a job's `when` keyword.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which predefined variable contains the absolute path to the cloned project on the runner?$gl$, $gl$[{"id":"a","text":"CI_PROJECT_DIR"},{"id":"b","text":"CI_COMMIT_SHA"},{"id":"c","text":"CI_PIPELINE_ID"},{"id":"d","text":"CI_JOB_NAME"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`CI_PROJECT_DIR` is the full path where the repository is checked out. `CI_COMMIT_SHA` is the commit hash, `CI_PIPELINE_ID` the pipeline ID, and `CI_JOB_NAME` the job name.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which predefined variable contains the absolute path to the cloned project on the runner?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A job needs a Postgres database for integration tests. Which keyword attaches it as a linked container?$gl$, $gl$[{"id":"a","text":"services"},{"id":"b","text":"image"},{"id":"c","text":"cache"},{"id":"d","text":"needs"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`services` attaches helper containers (e.g. `postgres`) accessible by hostname during the job. `image` is the job's own container, `cache` reuses files, and `needs` builds a DAG.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job needs a Postgres database for integration tests. Which keyword attaches it as a linked container?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$What does `parallel: 5` on a job do?$gl$, $gl$[{"id":"a","text":"Runs the job 5 times in parallel as separate instances"},{"id":"b","text":"Retries the job 5 times"},{"id":"c","text":"Limits the job to 5 minutes"},{"id":"d","text":"Requires 5 runners to be online before starting"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`parallel: N` creates N parallel instances of the job (each with `CI_NODE_INDEX`/`CI_NODE_TOTAL`), often used to split test suites. It is not retry, timeout, or a runner-count gate.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `parallel: 5` on a job do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which keyword defines per-job or global environment variables directly in `.gitlab-ci.yml`?$gl$, $gl$[{"id":"a","text":"variables"},{"id":"b","text":"env"},{"id":"c","text":"export"},{"id":"d","text":"params"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$The `variables` keyword defines CI/CD variables globally or per job in the YAML. `env`, `export`, and `params` are not GitLab CI keywords for declaring variables.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword defines per-job or global environment variables directly in `.gitlab-ci.yml`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A job has `artifacts: paths: [build/]` and `expire_in: 1 week`. What happens after one week?$gl$, $gl$[{"id":"a","text":"The job is deleted"},{"id":"b","text":"The stored artifacts for that job are removed automatically"},{"id":"c","text":"The pipeline reruns"},{"id":"d","text":"The cache is cleared"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`expire_in` controls how long artifacts are retained; after the period GitLab deletes those artifacts (unless kept as latest). It does not delete the job, rerun the pipeline, or clear cache.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job has `artifacts: paths: [build/]` and `expire_in: 1 week`. What happens after one week?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which keyword lets a job start before earlier-stage jobs finish, based on an explicit dependency list (DAG)?$gl$, $gl$[{"id":"a","text":"needs"},{"id":"b","text":"stage"},{"id":"c","text":"only"},{"id":"d","text":"tags"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`needs` creates a directed acyclic graph so a job runs as soon as its needed jobs complete, ignoring strict stage ordering. `stage` enforces ordering, `only` filters inclusion, and `tags` selects runners.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/needs.html","label":"GitLab Docs — needs / DAG pipelines"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword lets a job start before earlier-stage jobs finish, based on an explicit dependency list (DAG)?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 4, $gl$SINGLE$gl$::"QType", $gl$A pipeline must deploy to staging automatically but require a click for production. How is this typically modeled?$gl$, $gl$[{"id":"a","text":"Both jobs use when: always"},{"id":"b","text":"staging deploy uses when: on_success; production deploy uses when: manual with environment: production"},{"id":"c","text":"Both jobs use when: never"},{"id":"d","text":"Use only the build stage"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Automatic staging plus a manual production gate is the standard pattern: staging runs on success, production is a `when: manual` job with `environment: production` so a human approves the release.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"},{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A pipeline must deploy to staging automatically but require a click for production. How is this typically modeled?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `interruptible: true` on a job allow GitLab to do?$gl$, $gl$[{"id":"a","text":"Automatically cancel the job/pipeline if a newer pipeline starts for the same ref"},{"id":"b","text":"Pause the job for manual approval"},{"id":"c","text":"Retry the job indefinitely"},{"id":"d","text":"Run the job on any runner"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`interruptible: true` marks a job safe to cancel so GitLab can auto-cancel redundant running pipelines when a newer commit is pushed, saving CI minutes. It is not approval, retry, or runner selection.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `interruptible: true` on a job allow GitLab to do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What does mentioning `@username` in an issue or MR comment do?$gl$, $gl$[{"id":"a","text":"Assigns the issue to that user permanently"},{"id":"b","text":"Notifies (mentions) that user and creates a link to their profile"},{"id":"c","text":"Deletes that user"},{"id":"d","text":"Grants that user Owner access"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`@username` mentions the user, sending them a notification and linking their profile. It does not assign, delete, or change permissions.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does mentioning `@username` in an issue or MR comment do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which quick action assigns the current issue to a user from a comment?$gl$, $gl$[{"id":"a","text":"/assign @user"},{"id":"b","text":"/owner @user"},{"id":"c","text":"/give @user"},{"id":"d","text":"/take @user only"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`/assign @user` sets the assignee (and `/assign me` assigns yourself). `/owner`, `/give`, and `/take @user only` are not the assign quick action.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which quick action assigns the current issue to a user from a comment?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is an issue board list most commonly backed by?$gl$, $gl$[{"id":"a","text":"A label"},{"id":"b","text":"A commit"},{"id":"c","text":"A runner tag"},{"id":"d","text":"A cache key"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Board lists are typically created from labels (or assignees/milestones); moving a card between label lists updates the issue's labels. Commits, runner tags, and cache keys do not back board lists.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"},{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is an issue board list most commonly backed by?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$How do epics differ from milestones?$gl$, $gl$[{"id":"a","text":"Epics are time-boxed; milestones group unrelated commits"},{"id":"b","text":"Epics group related issues (often across projects) under an initiative; milestones track a time-boxed scope of work"},{"id":"c","text":"They are identical features"},{"id":"d","text":"Milestones are a Git concept"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Epics organize related issues (frequently across projects) toward a larger goal; milestones track a defined, often time-boxed set of issues/MRs with dates and progress. They are distinct, non-Git features.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/epics/","label":"GitLab Docs — Epics"},{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$How do epics differ from milestones?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about merge request approvals.$gl$, $gl$[{"id":"a","text":"You can require a minimum number of approvals before merging."},{"id":"b","text":"Approval rules can require specific users or groups (e.g. code owners)."},{"id":"c","text":"An approval can be configured to be removed when new commits are pushed."},{"id":"d","text":"Approvals are purely cosmetic and never block merging."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Approvals can enforce a minimum count, require specific approvers/groups, and optionally reset on new commits. They are an enforced merge gate, not cosmetic.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about merge request approvals.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Including `Closes #15` in a merge request description has what effect?$gl$, $gl$[{"id":"a","text":"It deletes issue #15 immediately"},{"id":"b","text":"It links the MR to issue #15 and closes it automatically when the MR merges to the default branch"},{"id":"c","text":"It assigns issue #15 to you"},{"id":"d","text":"It creates 15 new issues"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Closing keywords like `Closes #15` in an MR description link the issue and auto-close it upon merge to the default branch. It does not delete immediately, assign, or create issues.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Including `Closes #15` in a merge request description has what effect?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which quick action sets a milestone on an issue from a comment?$gl$, $gl$[{"id":"a","text":"/milestone %\"2.0 Release\""},{"id":"b","text":"/release 2.0"},{"id":"c","text":"/due 2.0"},{"id":"d","text":"/sprint 2.0"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`/milestone %"Milestone Name"` assigns a milestone via quick action. `/release`, `/due`, and `/sprint` are not the milestone quick action (`/due` sets a due date instead).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"},{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which quick action sets a milestone on an issue from a comment?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which role is the highest default privilege level for a project or group in GitLab?$gl$, $gl$[{"id":"a","text":"Owner"},{"id":"b","text":"Maintainer"},{"id":"c","text":"Developer"},{"id":"d","text":"Reporter"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Owner is the top default role, able to administer the project/group including deletion, visibility, and member/role management. Maintainer is below it; Developer/Reporter are lower still.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which role is the highest default privilege level for a project or group in GitLab?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which scanner inspects your own application source code (not dependencies) for insecure patterns without running it?$gl$, $gl$[{"id":"a","text":"Dependency Scanning"},{"id":"b","text":"SAST"},{"id":"c","text":"Secret Detection"},{"id":"d","text":"Container Scanning"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$SAST statically analyzes your source code for vulnerabilities. Dependency Scanning targets third-party libraries, Secret Detection finds credentials, and Container Scanning analyzes image OS/packages.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which scanner inspects your own application source code (not dependencies) for insecure patterns without running it?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A team wants every change to the default branch to be reviewed and to leave an auditable trail. Which combination best achieves this?$gl$, $gl$[{"id":"a","text":"Allow direct pushes and disable audit events"},{"id":"b","text":"Protect the branch, require MR approvals, and rely on audit events for change tracking"},{"id":"c","text":"Give all users Owner and remove approvals"},{"id":"d","text":"Use only Git stash"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Protecting the branch with required approvals enforces review, while audit events provide the immutable record of who changed what — together forming a strong compliance control. The other options weaken or remove controls.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"},{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A team wants every change to the default branch to be reviewed and to leave an auditable trail. Which combination best achieves this?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which project visibility level allows any authenticated user on the GitLab instance to view it, but not anonymous users?$gl$, $gl$[{"id":"a","text":"Public"},{"id":"b","text":"Internal"},{"id":"c","text":"Private"},{"id":"d","text":"Protected"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Internal visibility lets any signed-in instance user view the project; Public allows anyone (including anonymous), and Private restricts to members. "Protected" is not a visibility level.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"},{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which project visibility level allows any authenticated user on the GitLab instance to view it, but not anonymous users?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL good practices for handling secrets in GitLab CI/CD.$gl$, $gl$[{"id":"a","text":"Store secrets as masked, protected CI/CD variables instead of in the repo."},{"id":"b","text":"Use the short-lived CI_JOB_TOKEN or scoped tokens where possible."},{"id":"c","text":"Commit production passwords directly in .gitlab-ci.yml for convenience."},{"id":"d","text":"Rotate any credential that is detected as leaked."}]$gl$::jsonb, $gl$["a","b","d"]$gl$::jsonb, $gl$Best practice: keep secrets out of the repo (masked/protected variables), prefer short-lived/scoped tokens, and rotate leaked credentials. Committing production passwords into YAML is a serious anti-pattern.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL good practices for handling secrets in GitLab CI/CD.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Where do GitLab security scan results for an MR typically appear so reviewers can gate the merge?$gl$, $gl$[{"id":"a","text":"Only in email"},{"id":"b","text":"In the MR security widget / pipeline Security tab listing newly introduced vulnerabilities"},{"id":"c","text":"In the Git stash"},{"id":"d","text":"In the runner logs only"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Scan results surface in the MR security widget and pipeline Security tab, highlighting vulnerabilities introduced by the change so reviewers can require fixes before merging.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/dependency_scanning/","label":"GitLab Docs — Dependency scanning"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Where do GitLab security scan results for an MR typically appear so reviewers can gate the merge?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: The principle of least privilege suggests assigning users the lowest role that still lets them do their job (e.g. Reporter instead of Maintainer when they only need read access).$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Least privilege minimizes risk by granting only the access required; in GitLab that means choosing the lowest sufficient role (Guest/Reporter/Developer/Maintainer/Owner) for each user.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P2$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: The principle of least privilege suggests assigning users the lowest role that still lets them do their job (e.g. Reporter instead of Maintainer when they only need read access).$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$Which command shows the working tree status — which files are staged, modified, or untracked?$gl$, $gl$[{"id":"a","text":"git log"},{"id":"b","text":"git status"},{"id":"c","text":"git diff --cached"},{"id":"d","text":"git show"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git status` summarizes staged, modified, and untracked files plus branch tracking info. `git log` shows commit history, `git diff --cached` shows only the staged diff, and `git show` displays a single commit.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command shows the working tree status — which files are staged, modified, or untracked?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$You committed with a typo in the message and have not pushed yet. Which command edits the most recent commit message?$gl$, $gl$[{"id":"a","text":"git commit --amend"},{"id":"b","text":"git rebase --continue"},{"id":"c","text":"git revert HEAD"},{"id":"d","text":"git reset HEAD~1"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git commit --amend` rewrites the latest commit (message and/or staged content). `git revert` creates a new commit that undoes changes, and `git reset HEAD~1` moves the branch pointer back rather than editing the message.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You committed with a typo in the message and have not pushed yet. Which command edits the most recent commit message?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: A lightweight Git tag is essentially just a named pointer to a commit, while an annotated tag is a full object storing tagger, date, and a message.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Lightweight tags are simple refs to a commit; annotated tags (`git tag -a`) are stored as full objects with metadata and can be GPG-signed, which is why annotated tags are recommended for releases.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/tags/","label":"GitLab Docs — Tags"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: A lightweight Git tag is essentially just a named pointer to a commit, while an annotated tag is a full object storing tagger, date, and a message.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which command uploads your local `main` branch commits to the remote named `origin`?$gl$, $gl$[{"id":"a","text":"git fetch origin main"},{"id":"b","text":"git push origin main"},{"id":"c","text":"git pull origin main"},{"id":"d","text":"git clone origin main"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git push origin main` sends local commits to the remote branch. `git fetch`/`git pull` download from the remote, and `git clone` creates a new local copy of a repository.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command uploads your local `main` branch commits to the remote named `origin`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is a GitLab project primarily a container for?$gl$, $gl$[{"id":"a","text":"Only CI/CD runners"},{"id":"b","text":"A repository plus its issues, merge requests, CI/CD, wiki, and related features"},{"id":"c","text":"Only billing and subscription data"},{"id":"d","text":"A single user account"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A GitLab project bundles the Git repository together with issues, merge requests, pipelines, wiki, registry, and more. It is not limited to runners, billing, or a user account.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is a GitLab project primarily a container for?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A group Owner wants every new project under the group to inherit the same members and permissions automatically. Which structure achieves this?$gl$, $gl$[{"id":"a","text":"Create each project as a personal project and add members manually"},{"id":"b","text":"Place the projects in the group (or its subgroups); members and roles cascade down by inheritance"},{"id":"c","text":"Use a protected tag on each project"},{"id":"d","text":"Fork a template project for each new project"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Group and subgroup membership cascades to contained projects, so adding a member at the group level grants inherited access to its projects. Personal projects, tags, and forking do not provide group-wide inherited membership.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"},{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A group Owner wants every new project under the group to inherit the same members and permissions automatically. Which structure achieves this?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about the GitLab fork-based contribution workflow.$gl$, $gl$[{"id":"a","text":"A fork is a server-side copy of a project that you own and can push to."},{"id":"b","text":"You open a merge request from a branch in your fork targeting the upstream project."},{"id":"c","text":"Forking requires Owner access on the upstream project."},{"id":"d","text":"Maintainers of the upstream project can be allowed to edit the MR source branch."}]$gl$::jsonb, $gl$["a","b","d"]$gl$::jsonb, $gl$Forks are your own server-side copies; MRs go from your fork branch to upstream; and the "Allow commits from members who can merge to the target branch" option lets maintainers edit the source branch. Forking does NOT require Owner access — read access to a public/visible project is enough.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about the GitLab fork-based contribution workflow.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$In GitLab Flow, why is the main branch generally kept deployable at all times?$gl$, $gl$[{"id":"a","text":"So that broken code can be released faster"},{"id":"b","text":"Because feature work is integrated only after passing review and CI, keeping main stable and releasable"},{"id":"c","text":"Because main cannot be protected"},{"id":"d","text":"Because GitLab forbids feature branches"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$GitLab Flow keeps main releasable by merging only reviewed, CI-passing changes via merge requests. Main can and should be protected, and feature branches are central to the flow — not forbidden.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In GitLab Flow, why is the main branch generally kept deployable at all times?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is the role of a GitLab Runner?$gl$, $gl$[{"id":"a","text":"It stores the project's Git history"},{"id":"b","text":"It is the agent that picks up CI/CD jobs and executes them"},{"id":"c","text":"It renders the merge request diff"},{"id":"d","text":"It manages user permissions"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A GitLab Runner is the agent that polls GitLab for jobs and runs them (using an executor such as docker or shell). It does not store Git history, render diffs, or manage permissions.$gl$, $gl$[{"url":"https://docs.gitlab.com/runner/","label":"GitLab Docs — GitLab Runner"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the role of a GitLab Runner?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A pipeline uses a job with `trigger: include: child-pipeline.yml`. This creates which kind of pipeline relationship?$gl$, $gl$[{"id":"a","text":"A merge request pipeline"},{"id":"b","text":"A parent-child pipeline, where the parent triggers a separate child pipeline"},{"id":"c","text":"A scheduled pipeline"},{"id":"d","text":"A manual pipeline only"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Using `trigger` to run another configuration creates a parent-child (downstream) pipeline; the child runs as its own pipeline orchestrated by the parent. This is distinct from merge request, scheduled, or manual pipeline types.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/pipelines/downstream_pipelines.html","label":"GitLab Docs — Parent-child pipelines"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A pipeline uses a job with `trigger: include: child-pipeline.yml`. This creates which kind of pipeline relationship?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A `build` job produces a compiled binary that a later `test` job must use. Which keyword should `build` use so the file is passed forward reliably?$gl$, $gl$[{"id":"a","text":"cache:"},{"id":"b","text":"artifacts:"},{"id":"c","text":"services:"},{"id":"d","text":"variables:"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Build outputs that must reach later jobs should be declared as `artifacts`, which GitLab stores and passes to downstream jobs by default. `cache` is best-effort reuse between runs and is not a reliable hand-off mechanism.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"},{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A `build` job produces a compiled binary that a later `test` job must use. Which keyword should `build` use so the file is passed forward reliably?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about `rules` vs `only`/`except` in GitLab CI/CD.$gl$, $gl$[{"id":"a","text":"rules is the recommended, more flexible mechanism and can use rules:if and rules:changes."},{"id":"b","text":"only/except are older keywords and should not be combined with rules in the same job."},{"id":"c","text":"rules can set when and allow_failure per condition."},{"id":"d","text":"only/except can evaluate complex CI/CD variable expressions exactly like rules:if."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$rules is the modern, flexible approach (supports `if`, `changes`, per-rule `when`/`allow_failure`) and must not be mixed with only/except in the same job. only/except are simpler and do NOT support the full expression capability of rules:if.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about `rules` vs `only`/`except` in GitLab CI/CD.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 4, $gl$SINGLE$gl$::"QType", $gl$You want a CI/CD job to build and push a Docker image to the project's built-in image storage. Which GitLab feature is that storage?$gl$, $gl$[{"id":"a","text":"GitLab Pages"},{"id":"b","text":"The Container Registry"},{"id":"c","text":"The CI/CD cache"},{"id":"d","text":"Job artifacts"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The GitLab Container Registry is the integrated registry for storing/distributing Docker images per project (with predefined `CI_REGISTRY*` variables). Pages hosts static sites; cache/artifacts store build files, not container images.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/packages/container_registry/","label":"GitLab Docs — Container Registry"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want a CI/CD job to build and push a Docker image to the project's built-in image storage. Which GitLab feature is that storage?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A job named `pages` publishes the contents of its `public/` directory as a static website. Which GitLab feature does this?$gl$, $gl$[{"id":"a","text":"GitLab Pages"},{"id":"b","text":"Container Registry"},{"id":"c","text":"Environments"},{"id":"d","text":"Releases"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$GitLab Pages serves a static site from artifacts produced by a job conventionally named `pages` that exposes a `public/` directory. The Registry stores images, Environments track deployments, and Releases publish versioned release notes/assets.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/pages/","label":"GitLab Docs — GitLab Pages"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job named `pages` publishes the contents of its `public/` directory as a static website. Which GitLab feature does this?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which merge method results in a single commit on the target branch that combines all of the merge request's commits?$gl$, $gl$[{"id":"a","text":"Merge commit"},{"id":"b","text":"Squash and merge (squashing the MR commits into one)"},{"id":"c","text":"Fast-forward only"},{"id":"d","text":"Cherry-pick each commit individually"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Squash combines all MR commits into a single commit on the target branch, keeping history tidy. A plain merge commit preserves individual commits, fast-forward keeps them linearly, and cherry-pick is a separate manual operation.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which merge method results in a single commit on the target branch that combines all of the merge request's commits?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want a merge request to merge automatically as soon as its pipeline passes, without watching it. Which feature do you use?$gl$, $gl$[{"id":"a","text":"Draft status"},{"id":"b","text":"Merge when pipeline succeeds (auto-merge)"},{"id":"c","text":"Closing the linked issue"},{"id":"d","text":"Adding a milestone"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Auto-merge ("Merge when pipeline succeeds") queues the MR to merge automatically once the pipeline is green and other conditions are met. Draft blocks merging, and issues/milestones do not trigger merges.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/auto_merge.html","label":"GitLab Docs — Merge when pipeline succeeds"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want a merge request to merge automatically as soon as its pipeline passes, without watching it. Which feature do you use?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which feature lets you apply colored, named categories to issues and merge requests for filtering and board organization?$gl$, $gl$[{"id":"a","text":"Labels"},{"id":"b","text":"Tags"},{"id":"c","text":"Releases"},{"id":"d","text":"Runners"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Labels are colored, named categories applied to issues/MRs/epics, used for filtering and board lists. Git tags mark commits, releases publish versioned artifacts, and runners execute CI jobs.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which feature lets you apply colored, named categories to issues and merge requests for filtering and board organization?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which default role is required to administer project settings, manage members, and configure protected branches (short of full Owner)?$gl$, $gl$[{"id":"a","text":"Guest"},{"id":"b","text":"Reporter"},{"id":"c","text":"Developer"},{"id":"d","text":"Maintainer"}]$gl$::jsonb, $gl$["d"]$gl$::jsonb, $gl$Maintainer can manage project settings, members, and protected branches. Guest/Reporter are read-oriented, Developer can push to non-protected branches but not administer the project; Owner is the top-level role.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which default role is required to administer project settings, manage members, and configure protected branches (short of full Owner)?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: GitLab security scanners such as SAST and Secret Detection are typically run as jobs inside the CI/CD pipeline.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. GitLab security scanning (SAST, Secret Detection, Dependency Scanning, etc.) is delivered as CI/CD jobs (often via includable templates), so results appear in the pipeline and merge request security widget.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: GitLab security scanners such as SAST and Secret Detection are typically run as jobs inside the CI/CD pipeline.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$For compliance, an organization needs an immutable record of who changed group membership and when. Which capability provides this?$gl$, $gl$[{"id":"a","text":"CI/CD pipeline logs"},{"id":"b","text":"Audit events / audit logging"},{"id":"c","text":"Issue comments"},{"id":"d","text":"The container registry"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Audit events capture security/compliance-relevant changes (membership, permissions, settings) with actor and timestamp for review. Pipeline logs, issue comments, and the registry are not designed as the authoritative audit trail.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"},{"url":"https://docs.gitlab.com/ee/administration/compliance.html","label":"GitLab Docs — Compliance"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$For compliance, an organization needs an immutable record of who changed group membership and when. Which capability provides this?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What is the primary purpose of `git add`?$gl$, $gl$[{"id":"a","text":"To create a new branch"},{"id":"b","text":"To stage changes so they are included in the next commit"},{"id":"c","text":"To upload commits to the remote"},{"id":"d","text":"To delete files from history"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git add` moves working-tree changes into the staging area (index) for the next commit. Branching, pushing, and history rewriting use different commands.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the primary purpose of `git add`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which command commits all changes to already-tracked files without separately running `git add`?$gl$, $gl$[{"id":"a","text":"git commit -a -m \"msg\""},{"id":"b","text":"git commit --new -m \"msg\""},{"id":"c","text":"git add --commit -m \"msg\""},{"id":"d","text":"git push -a -m \"msg\""}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git commit -a -m "msg"` auto-stages modifications and deletions of tracked files, then commits. It does NOT include brand-new untracked files (those still need `git add`).$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/commit.html","label":"GitLab Docs — Commit changes to Git"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command commits all changes to already-tracked files without separately running `git add`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$You want to temporarily save uncommitted work including untracked files before switching context. Which command does that?$gl$, $gl$[{"id":"a","text":"git stash -u (or --include-untracked)"},{"id":"b","text":"git reset --hard"},{"id":"c","text":"git clean -fd"},{"id":"d","text":"git commit -u"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git stash -u` (`--include-untracked`) stashes modified tracked files plus untracked files, leaving a clean tree to restore later. `reset --hard`/`clean -fd` destroy changes, and `commit -u` is not valid.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/stash.html","label":"GitLab Docs — Git stash"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You want to temporarily save uncommitted work including untracked files before switching context. Which command does that?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `git pull --rebase` do differently from a plain `git pull`?$gl$, $gl$[{"id":"a","text":"It deletes local commits"},{"id":"b","text":"It fetches and then rebases your local commits on top of the updated remote branch instead of creating a merge commit"},{"id":"c","text":"It pushes instead of pulling"},{"id":"d","text":"It only fetches without integrating"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$`git pull --rebase` replays your local commits on top of the fetched remote tip, producing a linear history without a merge commit. Plain `git pull` merges instead. It does not delete commits or push.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/git_rebase.html","label":"GitLab Docs — Git rebase"},{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `git pull --rebase` do differently from a plain `git pull`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: A lightweight tag and a branch are the same thing in Git.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$False. Both are refs, but a branch is meant to move as you commit, while a tag is intended as a fixed marker on a specific commit (e.g. a release point) and does not advance automatically.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/tags/","label":"GitLab Docs — Tags"},{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: A lightweight tag and a branch are the same thing in Git.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which command lists which commit and author last modified each line of `app.py`?$gl$, $gl$[{"id":"a","text":"git blame app.py"},{"id":"b","text":"git log app.py"},{"id":"c","text":"git diff app.py"},{"id":"d","text":"git show app.py"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git blame app.py` annotates each line with the commit, author, and timestamp that last changed it. `git log` shows commit history, `diff` shows changes, and `show` displays a commit.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command lists which commit and author last modified each line of `app.py`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$Which command downloads new commits and refs from `origin` without changing your working branch?$gl$, $gl$[{"id":"a","text":"git fetch origin"},{"id":"b","text":"git pull origin"},{"id":"c","text":"git merge origin"},{"id":"d","text":"git push origin"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`git fetch origin` updates remote-tracking refs only. `git pull` also integrates them into the current branch, `git merge` combines branches, and `git push` uploads commits.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which command downloads new commits and refs from `origin` without changing your working branch?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `git checkout -- file.txt` (or `git restore file.txt`) do?$gl$, $gl$[{"id":"a","text":"Stages file.txt"},{"id":"b","text":"Discards unstaged changes in file.txt, restoring it to the last committed version"},{"id":"c","text":"Deletes file.txt from history"},{"id":"d","text":"Creates a branch named file.txt"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$It reverts working-tree changes for that file to the committed state, discarding unstaged edits. It does not stage, rewrite history, or create a branch.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `git checkout -- file.txt` (or `git restore file.txt`) do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Git and GitLab Fundamentals$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about Git as a distributed VCS.$gl$, $gl$[{"id":"a","text":"Each clone contains the full project history."},{"id":"b","text":"You can commit locally without network access."},{"id":"c","text":"A central server is mandatory for making any commit."},{"id":"d","text":"Branching and merging are core, lightweight operations."}]$gl$::jsonb, $gl$["a","b","d"]$gl$::jsonb, $gl$Distributed Git gives every clone full history, allows offline local commits, and treats branching/merging as cheap operations. A central server is a convention (e.g. GitLab) but not required to commit.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/git/","label":"GitLab Docs — Git basics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about Git as a distributed VCS.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What is the recommended way to integrate a finished feature branch into main in GitLab?$gl$, $gl$[{"id":"a","text":"Push directly to main"},{"id":"b","text":"Open a merge request from the feature branch to main and merge after review/CI"},{"id":"c","text":"Email the diff to a maintainer"},{"id":"d","text":"Rename main to the feature branch"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Open an MR from the feature branch targeting main; after review and a green pipeline it is merged. Direct pushes bypass review/CI, and emailing/renaming are not GitLab workflows.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"},{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is the recommended way to integrate a finished feature branch into main in GitLab?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which protected-branch capability requires that the person who pushed/authored a change cannot also be its sole approver?$gl$, $gl$[{"id":"a","text":"Prevent approval by the author / separation-of-duties approval settings"},{"id":"b","text":"Squash commits"},{"id":"c","text":"Delete source branch"},{"id":"d","text":"Fast-forward merge"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$GitLab approval settings can prevent authors (and optionally committers) from approving their own MRs, enforcing separation of duties. Squash, delete-source-branch, and fast-forward are merge behaviors, not approval controls.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"},{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which protected-branch capability requires that the person who pushed/authored a change cannot also be its sole approver?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the target branch field of a merge request specify?$gl$, $gl$[{"id":"a","text":"The branch the source changes will be merged into"},{"id":"b","text":"The branch that contains the proposed changes"},{"id":"c","text":"The runner that builds the MR"},{"id":"d","text":"The label applied to the MR"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$The target branch is where the MR's changes will land (often the default branch). The source branch holds the proposed changes; runners and labels are unrelated to this field.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the target branch field of a merge request specify?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about protected branches and merge requests working together.$gl$, $gl$[{"id":"a","text":"Setting push to \"No one\" forces changes through merge requests."},{"id":"b","text":"You can require approvals before a protected branch MR can merge."},{"id":"c","text":"Code owner approval can be required for protected branches."},{"id":"d","text":"Protected branches automatically merge all open MRs."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Protecting a branch (no direct push) plus required approvals and optional code-owner approval enforces a reviewed MR workflow. Protected branches do NOT auto-merge open MRs.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/protected_branches.html","label":"GitLab Docs — Protected branches"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about protected branches and merge requests working together.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Why might a team choose "Squash and merge" as the default merge method?$gl$, $gl$[{"id":"a","text":"To preserve every WIP commit on main"},{"id":"b","text":"To keep the target branch history clean with one tidy commit per merge request"},{"id":"c","text":"To delete the target branch"},{"id":"d","text":"To skip code review"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Squashing condenses an MR's many work-in-progress commits into a single coherent commit on the target branch, keeping history clean. It does not delete branches or bypass review.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/methods/","label":"GitLab Docs — Merge methods"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Why might a team choose "Squash and merge" as the default merge method?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A subgroup `team-a` is under group `engineering`. A user added as Developer on `engineering` has what access to projects in `team-a`?$gl$, $gl$[{"id":"a","text":"No access at all"},{"id":"b","text":"Inherited Developer access to projects in team-a via group membership cascade"},{"id":"c","text":"Owner access automatically"},{"id":"d","text":"Read-only regardless of role"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Membership cascades down the namespace: a Developer on `engineering` inherits Developer access to subgroups like `team-a` and their projects (unless further restricted). It is neither no access nor automatic Owner.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/","label":"GitLab Docs — Groups"},{"url":"https://docs.gitlab.com/ee/user/group/subgroups/","label":"GitLab Docs — Subgroups"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A subgroup `team-a` is under group `engineering`. A user added as Developer on `engineering` has what access to projects in `team-a`?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$In a fork-based contribution, where do you push your changes?$gl$, $gl$[{"id":"a","text":"Directly to the upstream default branch"},{"id":"b","text":"To a branch in your own fork, then open a merge request to upstream"},{"id":"c","text":"To the upstream wiki"},{"id":"d","text":"To the container registry"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$You push to a branch in your fork (which you own) and open an MR from there to upstream. You cannot push to upstream without access, and the wiki/registry are not contribution paths.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$In a fork-based contribution, where do you push your changes?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which GitLab Flow practice keeps production deployable and traceable?$gl$, $gl$[{"id":"a","text":"Committing experimental code straight to the production branch"},{"id":"b","text":"Merging only reviewed, CI-passing changes forward through environment/main branches via merge requests"},{"id":"c","text":"Force-pushing to production nightly"},{"id":"d","text":"Disabling pipelines for production"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$GitLab Flow promotes only reviewed, tested changes forward via MRs, keeping production deployable and changes traceable. Direct/experimental commits or force-pushes to production undermine stability and traceability.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/topics/gitlab_flow.html","label":"GitLab Docs — GitLab Flow"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which GitLab Flow practice keeps production deployable and traceable?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Source Code Management and Workflows$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does adding `upstream` as a remote let a fork owner do?$gl$, $gl$[{"id":"a","text":"Push directly to the original project"},{"id":"b","text":"Fetch the latest changes from the original project to keep the fork in sync"},{"id":"c","text":"Delete the original project"},{"id":"d","text":"Bypass merge requests"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$An `upstream` remote lets the fork owner fetch and merge/rebase the original project's latest changes to stay current. It does not grant push access or bypass MRs.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/repository/forking_workflow.html","label":"GitLab Docs — Fork a project"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does adding `upstream` as a remote let a fork owner do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What is a GitLab CI/CD pipeline?$gl$, $gl$[{"id":"a","text":"A single Git branch"},{"id":"b","text":"A collection of jobs grouped into stages that automate build, test, and deploy"},{"id":"c","text":"A user role"},{"id":"d","text":"A container image registry"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$A pipeline is the top-level CI/CD construct: jobs organized into ordered stages that automate building, testing, and deploying. It is not a branch, role, or registry.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/","label":"GitLab Docs — CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What is a GitLab CI/CD pipeline?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Within one stage, if two jobs are defined, how do they execute (given enough runners)?$gl$, $gl$[{"id":"a","text":"Sequentially, alphabetically"},{"id":"b","text":"In parallel"},{"id":"c","text":"Only the last one runs"},{"id":"d","text":"They merge into a single job"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Jobs in the same stage run in parallel (subject to runner availability); the pipeline advances only when all of them succeed. They are not serialized or merged.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#stages","label":"GitLab Docs — CI/CD stages"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Within one stage, if two jobs are defined, how do they execute (given enough runners)?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which keyword would you use to ensure a job runs even if a previous-stage job failed (e.g. for notifications)?$gl$, $gl$[{"id":"a","text":"when: always"},{"id":"b","text":"when: on_success"},{"id":"c","text":"when: never"},{"id":"d","text":"allow_failure: false"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`when: always` runs the job regardless of earlier success/failure, useful for notifications/cleanup. `on_success` (default) skips it on failure, `never` disables it, and `allow_failure` does not control run conditions.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword would you use to ensure a job runs even if a previous-stage job failed (e.g. for notifications)?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A job should only run on the default branch. Which rule is correct?$gl$, $gl$[{"id":"a","text":"rules: - if: $CI_COMMIT_BRANCH == $CI_DEFAULT_BRANCH"},{"id":"b","text":"rules: - if: $CI_MERGE_REQUEST_IID"},{"id":"c","text":"only: tags"},{"id":"d","text":"when: manual"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Comparing `$CI_COMMIT_BRANCH` to `$CI_DEFAULT_BRANCH` restricts the job to the default branch. The MR variable matches MR pipelines, `only: tags` matches tags, and `when: manual` only changes trigger mode.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/#rules","label":"GitLab Docs — CI/CD rules"},{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A job should only run on the default branch. Which rule is correct?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about artifacts.$gl$, $gl$[{"id":"a","text":"Artifacts can be browsed/downloaded from the GitLab UI."},{"id":"b","text":"Artifacts can be passed to jobs in later stages by default."},{"id":"c","text":"expire_in controls how long artifacts are retained."},{"id":"d","text":"Artifacts are the same as cache and have identical guarantees."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Artifacts are stored by GitLab, downloadable, passed downstream by default, and expire via `expire_in`. They are NOT the same as cache — artifacts are reliable hand-offs while cache is best-effort.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"},{"url":"https://docs.gitlab.com/ee/ci/caching/","label":"GitLab Docs — Caching in CI/CD"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about artifacts.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which predefined variable holds the full commit SHA of the pipeline's commit?$gl$, $gl$[{"id":"a","text":"CI_COMMIT_SHA"},{"id":"b","text":"CI_PIPELINE_SOURCE"},{"id":"c","text":"CI_JOB_ID"},{"id":"d","text":"CI_PROJECT_NAME"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`CI_COMMIT_SHA` is the commit hash being built. `CI_PIPELINE_SOURCE` is what triggered the pipeline, `CI_JOB_ID` the job ID, and `CI_PROJECT_NAME` the project name.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which predefined variable holds the full commit SHA of the pipeline's commit?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A deploy job uses `environment: name: staging`. Where can you see the deployment history for staging?$gl$, $gl$[{"id":"a","text":"In the Git stash"},{"id":"b","text":"On the project's Environments page (Deployments)"},{"id":"c","text":"In the container registry tags"},{"id":"d","text":"In the issue board"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Declaring an environment records deployments visible on the Environments/Deployments page, including history and the ability to re-deploy or roll back. Stash, registry, and boards do not track deployments.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/environments/","label":"GitLab Docs — Environments and deployments"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A deploy job uses `environment: name: staging`. Where can you see the deployment history for staging?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which keyword would let a job download artifacts from only a specific named job in an earlier stage?$gl$, $gl$[{"id":"a","text":"dependencies: [build_linux]"},{"id":"b","text":"cache: build_linux"},{"id":"c","text":"image: build_linux"},{"id":"d","text":"stage: build_linux"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`dependencies: [build_linux]` restricts artifact downloads to that job. `cache`, `image`, and `stage` serve different purposes and do not scope artifact fetching.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/jobs/job_artifacts.html","label":"GitLab Docs — Job artifacts"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword would let a job download artifacts from only a specific named job in an earlier stage?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 4, $gl$SINGLE$gl$::"QType", $gl$You need build → test → deploy where deploy starts immediately after its specific build job (skip waiting for unrelated test jobs). What do you use?$gl$, $gl$[{"id":"a","text":"parallel on deploy"},{"id":"b","text":"needs: [\"build_app\"] on the deploy job to form a DAG"},{"id":"c","text":"allow_failure on test jobs"},{"id":"d","text":"cache:key on deploy"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Adding `needs: ["build_app"]` to deploy creates a DAG so deploy runs as soon as `build_app` completes, regardless of unrelated jobs/stages. `parallel`, `allow_failure`, and `cache:key` do not change ordering this way.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/needs.html","label":"GitLab Docs — needs / DAG pipelines"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$You need build → test → deploy where deploy starts immediately after its specific build job (skip waiting for unrelated test jobs). What do you use?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the `image:` keyword at the top level of `.gitlab-ci.yml` (outside any job) define?$gl$, $gl$[{"id":"a","text":"The default container image used by all jobs unless they override it"},{"id":"b","text":"The Git branch to build"},{"id":"c","text":"The runner host"},{"id":"d","text":"The artifact retention"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$A top-level `image` sets the default job container; individual jobs can override it with their own `image`. It does not pick branches, runner hosts, or artifact retention.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the `image:` keyword at the top level of `.gitlab-ci.yml` (outside any job) define?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which keyword delays a job's start by a configured period after it becomes eligible?$gl$, $gl$[{"id":"a","text":"when: delayed (with start_in)"},{"id":"b","text":"timeout"},{"id":"c","text":"retry"},{"id":"d","text":"interruptible"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`when: delayed` with `start_in: <duration>` schedules the job to start after a delay (e.g. delayed rollouts). `timeout` caps runtime, `retry` re-runs failures, and `interruptible` enables auto-cancel.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which keyword delays a job's start by a configured period after it becomes eligible?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$How do you reuse a common job definition defined as `.deploy_base` for two deploy jobs?$gl$, $gl$[{"id":"a","text":"extends: .deploy_base in each deploy job"},{"id":"b","text":"include: .deploy_base"},{"id":"c","text":"needs: .deploy_base"},{"id":"d","text":"trigger: .deploy_base"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`extends: .deploy_base` inherits and lets each job override the hidden template's configuration. `include` is for external files, `needs` builds a DAG, and `trigger` starts downstream pipelines.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$How do you reuse a common job definition defined as `.deploy_base` for two deploy jobs?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$CI/CD Pipelines$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does `coverage: '/Total.*?(\d+\.\d+)%/'` in a job do?$gl$, $gl$[{"id":"a","text":"Sets the test timeout"},{"id":"b","text":"Extracts a code coverage percentage from job output to display in the UI/MR"},{"id":"c","text":"Defines artifacts"},{"id":"d","text":"Selects a runner"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$The `coverage` keyword applies a regex to the job log to capture a coverage percentage that GitLab then displays on the pipeline/MR. It is unrelated to timeouts, artifacts, or runner selection.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/yaml/","label":"GitLab Docs — .gitlab-ci.yml keyword reference"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does `coverage: '/Total.*?(\d+\.\d+)%/'` in a job do?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 1, $gl$SINGLE$gl$::"QType", $gl$What does referencing `#42` in an issue or MR comment create?$gl$, $gl$[{"id":"a","text":"A deletion of issue 42"},{"id":"b","text":"A cross-link/reference to issue number 42"},{"id":"c","text":"A new merge request"},{"id":"d","text":"An assignment to user 42"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$In GitLab, `#42` links issue 42 (and `!42` links MR 42). It creates a navigable cross-reference, not a deletion, MR, or assignment.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does referencing `#42` in an issue or MR comment create?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which feature is best for grouping related issues across multiple projects under one initiative?$gl$, $gl$[{"id":"a","text":"Epics"},{"id":"b","text":"Labels only"},{"id":"c","text":"Git tags"},{"id":"d","text":"Snippets"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Epics (a group-level feature) collect related issues that may span projects under a single initiative with their own timeline. Labels categorize but do not provide hierarchy; tags/snippets are unrelated.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/group/epics/","label":"GitLab Docs — Epics"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which feature is best for grouping related issues across multiple projects under one initiative?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$A quick action `/spend 2h` on an issue does what?$gl$, $gl$[{"id":"a","text":"Records 2 hours of time spent on the issue"},{"id":"b","text":"Sets a 2-hour due date"},{"id":"c","text":"Closes the issue after 2 hours"},{"id":"d","text":"Assigns 2 users"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`/spend 2h` logs time spent (paired with `/estimate` for the estimate). It is not a due date, auto-close timer, or assignment action.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A quick action `/spend 2h` on an issue does what?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$Which capability lets you see remaining vs completed work for a milestone over its timeframe?$gl$, $gl$[{"id":"a","text":"Burndown/burnup charts"},{"id":"b","text":"CI/CD cache"},{"id":"c","text":"Container registry"},{"id":"d","text":"Git reflog"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Milestone burndown/burnup charts visualize progress (remaining/completed work) across the milestone period. Cache, registry, and reflog are unrelated to milestone tracking.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/milestones/","label":"GitLab Docs — Milestones"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which capability lets you see remaining vs completed work for a milestone over its timeframe?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$How does a label-based issue board column relate to issue labels?$gl$, $gl$[{"id":"a","text":"Each board list maps to a label; moving a card changes the issue's labels accordingly"},{"id":"b","text":"Board lists ignore labels entirely"},{"id":"c","text":"A board can only have one list"},{"id":"d","text":"Boards delete labels when used"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$Label-based board lists correspond to labels; dragging a card between lists updates the issue's labels to match the destination list. Boards support many lists and do not delete labels.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issue_board.html","label":"GitLab Docs — Issue boards"},{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$How does a label-based issue board column relate to issue labels?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about GitLab issues.$gl$, $gl$[{"id":"a","text":"Issues can have assignees, labels, milestones, and a due date."},{"id":"b","text":"Issues support threaded discussion and mentions."},{"id":"c","text":"Closing keywords in a merged MR can auto-close linked issues."},{"id":"d","text":"Issues are stored as Git tags in the repository."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$Issues support assignees, labels, milestones, due dates, threaded discussion/mentions, and auto-close via MR keywords. They are stored in GitLab's database, NOT as Git tags in the repo.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"},{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/","label":"GitLab Docs — Merge requests"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about GitLab issues.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Project Management and Collaboration$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$What does the `/label ~bug` quick action do in an issue?$gl$, $gl$[{"id":"a","text":"Adds the bug label to the issue"},{"id":"b","text":"Deletes all labels"},{"id":"c","text":"Closes the issue"},{"id":"d","text":"Creates a label called issue"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$`/label ~bug` applies the `bug` label (`/unlabel` removes labels). It does not delete all labels, close the issue, or create a label named "issue".$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/labels.html","label":"GitLab Docs — Labels"},{"url":"https://docs.gitlab.com/ee/user/project/issues/","label":"GitLab Docs — Issues"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$What does the `/label ~bug` quick action do in an issue?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which default role can push to non-protected branches but cannot manage project members or settings?$gl$, $gl$[{"id":"a","text":"Guest"},{"id":"b","text":"Reporter"},{"id":"c","text":"Developer"},{"id":"d","text":"Owner"}]$gl$::jsonb, $gl$["c"]$gl$::jsonb, $gl$Developer can push to non-protected branches and open MRs but cannot administer members/settings/protected branches (that needs Maintainer/Owner). Guest/Reporter cannot push code.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which default role can push to non-protected branches but cannot manage project members or settings?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which scanner is specifically aimed at finding committed credentials such as tokens and keys?$gl$, $gl$[{"id":"a","text":"SAST"},{"id":"b","text":"Secret Detection"},{"id":"c","text":"Dependency Scanning"},{"id":"d","text":"Container Scanning"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Secret Detection scans code and history for leaked credentials. SAST analyzes code logic, Dependency Scanning checks libraries, and Container Scanning inspects image packages.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which scanner is specifically aimed at finding committed credentials such as tokens and keys?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$An organization needs to prove that every production change was reviewed by someone other than the author. Which combination supports this audit requirement?$gl$, $gl$[{"id":"a","text":"Allow self-approval and disable logging"},{"id":"b","text":"Require MR approvals with author self-approval prevented, plus audit events"},{"id":"c","text":"Give all users Owner"},{"id":"d","text":"Use only Git tags"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Requiring approvals while preventing the author from approving enforces independent review (separation of duties), and audit events provide the immutable proof. Self-approval or universal Owner undermines the control.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/project/merge_requests/approvals/","label":"GitLab Docs — Merge request approvals"},{"url":"https://docs.gitlab.com/ee/administration/audit_events.html","label":"GitLab Docs — Audit events"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$An organization needs to prove that every production change was reviewed by someone other than the author. Which combination supports this audit requirement?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$SINGLE$gl$::"QType", $gl$Which project visibility allows anyone, including users who are not signed in, to view the project?$gl$, $gl$[{"id":"a","text":"Private"},{"id":"b","text":"Internal"},{"id":"c","text":"Public"},{"id":"d","text":"Restricted"}]$gl$::jsonb, $gl$["c"]$gl$::jsonb, $gl$Public visibility lets anyone (including anonymous visitors) view the project. Internal requires sign-in, Private restricts to members, and "Restricted" is not a visibility level.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/permissions.html","label":"GitLab Docs — Roles and permissions"},{"url":"https://docs.gitlab.com/ee/user/project/","label":"GitLab Docs — Projects"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Which project visibility allows anyone, including users who are not signed in, to view the project?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$MULTI$gl$::"QType", $gl$Select ALL true statements about GitLab security scanning.$gl$, $gl$[{"id":"a","text":"Scanners typically run as CI/CD jobs, often added via include templates."},{"id":"b","text":"Findings appear in the pipeline Security tab and the MR security widget."},{"id":"c","text":"SAST analyzes source code without executing it."},{"id":"d","text":"Security scanners replace the need for code review."}]$gl$::jsonb, $gl$["a","b","c"]$gl$::jsonb, $gl$GitLab scanners run as CI jobs (added via templates), surface results in the pipeline/MR, and SAST is static analysis. They complement — but do NOT replace — human code review and approvals.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/sast/","label":"GitLab Docs — SAST"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$Select ALL true statements about GitLab security scanning.$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 3, $gl$SINGLE$gl$::"QType", $gl$A live token was leaked in a commit. Beyond removing it from code, what is essential?$gl$, $gl$[{"id":"a","text":"Nothing else is needed"},{"id":"b","text":"Revoke/rotate the token because it remains recoverable in Git history"},{"id":"c","text":"Make the project public"},{"id":"d","text":"Add it to .gitignore"}]$gl$::jsonb, $gl$["b"]$gl$::jsonb, $gl$Because Git history retains the secret, deleting it from the latest code is insufficient — the token must be revoked/rotated. `.gitignore` only affects future tracking, not existing history.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$A live token was leaked in a commit. Beyond removing it from code, what is essential?$gl$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $gl$Security and Compliance Basics$gl$, 2, $gl$TRUE_FALSE$gl$::"QType", $gl$True or False: Storing a deploy key or token as a masked, protected CI/CD variable is more secure than committing it to the repository.$gl$, $gl$[{"id":"a","text":"True"},{"id":"b","text":"False"}]$gl$::jsonb, $gl$["a"]$gl$::jsonb, $gl$True. Masked/protected variables keep secrets out of Git history, hide them in logs, and limit exposure to protected branches/tags — far safer than committing them into the repository.$gl$, $gl$[{"url":"https://docs.gitlab.com/ee/ci/variables/","label":"GitLab Docs — CI/CD variables"},{"url":"https://docs.gitlab.com/ee/user/application_security/secret_detection/","label":"GitLab Docs — Secret detection"}]$gl$::jsonb, $gl$PUBLISHED$gl$::"QStatus", $gl$manual:gitlab-seed$gl$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $gl$GLCA-P3$gl$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $gl$True or False: Storing a deploy key or token as a masked, protected CI/CD variable is more secure than committing it to the repository.$gl$);
